// src/main.ts
import 'dotenv/config';
import cookieParser from 'cookie-parser';
import helmet from 'helmet';
import { json } from 'express';
import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { ValidationPipe } from '@nestjs/common';
import { NestExpressApplication } from '@nestjs/platform-express';
import { validateEnvironment } from './config/env.validation';

async function bootstrap() {
  // Validate environment variables before starting server
  // This will throw an error with helpful messages if any are missing or invalid
  validateEnvironment();

  const app = await NestFactory.create<NestExpressApplication>(AppModule);

  // behind proxy/CDN so secure cookies work
  app.set('trust proxy', 1);

  // Security headers via Helmet
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          styleSrc: ["'self'", "'unsafe-inline'"],
          scriptSrc: ["'self'"],
          imgSrc: ["'self'", 'data:', 'https:'],
        },
      },
      hsts: {
        maxAge: 31536000, // 1 year
        includeSubDomains: true,
        preload: true,
      },
      frameguard: {
        action: 'deny', // Prevent clickjacking
      },
      noSniff: true, // Prevent MIME sniffing
      xssFilter: true, // Enable XSS filter
    }),
  );

  // Request body size limit (prevent large payload attacks)
  app.use(json({ limit: '1mb' }));

  // parse cookies (for lg_jwt)
  app.use(cookieParser());

  // CORS for your site
  app.enableCors({
    origin: ['https://lazygolfing.com', 'https://www.lazygolfing.com', 'https://lazygolfing-com.pages.dev'],
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
  });

  // DTO validation / transformation
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true, // Reject unexpected fields for security
      transform: true,
      transformOptions: { enableImplicitConversion: true },
    }),
  );

  await app.listen(Number(process.env.PORT) || 3000, '0.0.0.0');
}
bootstrap();

