// src/auth/auth.controller.ts
import { Controller, Get, Post, Req, Res, UseGuards } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { Throttle } from '@nestjs/throttler';
import type { Request, Response } from 'express';
import { AuthService } from './auth.service';
import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';
import { generateCsrfToken } from './csrf.util';
import { CsrfGuard } from './csrf.guard';

@Controller('auth')
export class AuthController {
  constructor(
    private readonly auth: AuthService,
    private readonly auditLog: AuditLogService,
  ) {}

  /**
   * Kick off Google OAuth.
   * The Passport guard will handle the redirect to Google.
   */
  @Get('google')
  @UseGuards(AuthGuard('google'))
  async googleAuth() {
    // Intentionally empty – the guard handles the redirect flow.
    return;
  }

  /**
   * Google OAuth callback.
   * Creates/validates the user, mints a JWT, sets it as an HttpOnly cookie,
   * then redirects back to the SPA.
   */
  @Get('google/redirect')
  @UseGuards(AuthGuard('google'))
  async googleRedirect(
    @Req() req: Request & { user?: any },
    @Res() res: Response,
  ) {
    if (!req.user) {
      return res.redirect('https://lazygolfing.com/login?error=oauth_no_user');
    }

    const oAuthUser = req.user;
    const user = await this.auth.validateOrCreateOAuthUser(oAuthUser);
    const token = this.auth.createToken(user);

    const isProd = process.env.NODE_ENV === 'production';

    // Cookie: HttpOnly, cross-subdomain, and cross-site for api<>www
    res.cookie('lg_jwt', token, {
      httpOnly: true,
      secure: isProd,                     // must be true with SameSite=None
      sameSite: isProd ? 'none' : 'lax',  // 'none' so the cookie is sent cross-site
      domain: isProd ? '.lazygolfing.com' : undefined,
      path: '/',
      maxAge: 1000 * 60 * 60 * 24 * 7, // 7 days
    });

    // Generate and set CSRF token for double-submit cookie pattern
    const csrfToken = generateCsrfToken();
    res.cookie('csrf_token', csrfToken, {
      httpOnly: false,                    // Must be readable by JavaScript
      secure: isProd,
      sameSite: isProd ? 'none' : 'lax',
      domain: isProd ? '.lazygolfing.com' : undefined,
      path: '/',
      maxAge: 1000 * 60 * 60 * 24 * 7, // 7 days (same as JWT)
    });

    return res.redirect('https://lazygolfing.com/profile');
  }

  /**
   * Clear auth cookie (logout).
   * Changed to POST to prevent CSRF attacks.
   * Protected by CSRF guard.
   */
  @Post('logout')
  @UseGuards(CsrfGuard)
  async logout(@Req() req: Request, @Res() res: Response) {
    // Get user ID from token before clearing cookie (for audit log)
    const token = (req as any).cookies?.lg_jwt as string | undefined;
    if (token) {
      const payload = this.auth.verifyToken(token);
      if (payload) {
        // Audit log: logout event
        await this.auditLog.log(payload.sub, AuditAction.LOGOUT, 'Auth');
      }
    }

    const isProd = process.env.NODE_ENV === 'production';

    // Clear JWT cookie
    res.clearCookie('lg_jwt', {
      httpOnly: true,
      secure: isProd,
      sameSite: isProd ? 'none' : 'lax',
      domain: isProd ? '.lazygolfing.com' : undefined,
      path: '/',
    });

    // Clear CSRF token cookie
    res.clearCookie('csrf_token', {
      httpOnly: false,
      secure: isProd,
      sameSite: isProd ? 'none' : 'lax',
      domain: isProd ? '.lazygolfing.com' : undefined,
      path: '/',
    });

    return res.status(204).send();
  }

  /**
   * Session probe that actually verifies the JWT.
   * Rate limited to 20 requests per minute to prevent abuse.
   */
  @Get('session')
  @Throttle({ session: { limit: 20, ttl: 60000 } })
  async session(@Req() req: Request, @Res() res: Response) {
    const token = (req as any).cookies?.lg_jwt as string | undefined;
    if (!token) return res.json({ authenticated: false });

    const payload = this.auth.verifyToken(token);
    if (!payload) return res.json({ authenticated: false });

    return res.json({ authenticated: true, userId: payload.sub, email: payload.email });
  }
}

