     1→import { Injectable } from '@nestjs/common';
     2→import { PrismaService } from '../prisma/prisma.service';
     3→import { JwtService } from '@nestjs/jwt';
     4→import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';
     5→
     6→export type OAuthUser = {
     7→  email: string;
     8→  providerId: string;
     9→  provider?: string;          // 'google' (default), room for others later
    10→  firstName?: string;
    11→  lastName?: string;
    12→  avatarUrl?: string | null;  // Google "picture"
    13→  locale?: string | null;     // Google "locale"
    14→  emailVerified?: boolean;    // Google "email_verified"
    15→  hostedDomain?: string | null; // Google "hd" (if any)
    16→};
    17→
    18→export type TokenPayload = { sub: string; email: string; iat?: number; exp?: number };
    19→
    20→@Injectable()
    21→export class AuthService {
    22→  constructor(
    23→    private prisma: PrismaService,
    24→    private jwt: JwtService,
    25→    private auditLog: AuditLogService,
    26→  ) {}
    27→
    28→  /**
    29→   * Upsert User, ensure Player exists, and persist OAuth profile fields.
    30→   * Returns a minimal shape for token creation.
    31→   */
    32→  async validateOrCreateOAuthUser(o: OAuthUser): Promise<{ id: string; email: string }> {
    33→    const email = o.email.toLowerCase();
    34→    const firstName = o.firstName ?? 'Golfer';
    35→    const lastName = o.lastName ?? 'User';
    36→    const provider = o.provider ?? 'google';
    37→    const now = new Date();
    38→
    39→    const user = await this.prisma.user.upsert({
    40→      where: { email },
    41→      update: {
    42→        provider,
    43→        providerId: o.providerId,
    44→        firstName,
    45→        lastName,
    46→        // only set when provided; undefined means "leave as-is" in Prisma
    47→        avatarUrl: o.avatarUrl ?? undefined,
    48→        locale: o.locale ?? undefined,
    49→        emailVerified: o.emailVerified ?? undefined,
    50→        hostedDomain: o.hostedDomain ?? undefined,
    51→        lastLoginAt: now,
    52→      },
    53→      create: {
    54→        email,
    55→        provider,
    56→        providerId: o.providerId,
    57→        firstName,
    58→        lastName,
    59→        avatarUrl: o.avatarUrl ?? null,
    60→        locale: o.locale ?? null,
    61→        emailVerified: o.emailVerified ?? false,
    62→        hostedDomain: o.hostedDomain ?? null,
    63→        lastLoginAt: now,
    64→        player: {
    65→          create: {
    66→            firstName,
    67→            lastName,
    68→          },
    69→        },
    70→      },
    71→      include: { player: true },
    72→    });
    73→
    74→    // In case user existed but no Player row was ever created
    75→    if (!user.player) {
    76→      await this.prisma.player.create({
    77→        data: {
    78→          userId: user.id,
    79→          firstName,
    80→          lastName,
    81→        },
    82→      });
    83→    }
    84→
    85→    // Assign roles on first login or ensure they exist
    86→    await this.ensureUserRoles(user.id, email);
    87→
    88→    // Audit log: successful login
    89→    await this.auditLog.log(user.id, AuditAction.LOGIN, 'Auth', {
    90→      provider,
    91→      email: user.email,
    92→    });
    93→
    94→    return { id: user.id, email: user.email };
    95→  }
    96→
    97→  /**
    98→   * Ensure user has appropriate roles
    99→   * - info@lazygolfing.com gets admin role
   100→   * - All other users get user role
   101→   */
   102→  private async ensureUserRoles(userId: string, email: string): Promise<void> {
   103→    const isAdmin = email.toLowerCase() === 'info@lazygolfing.com';
   104→
   105→    // Get roles
   106→    const [adminRole, userRole] = await Promise.all([
   107→      this.prisma.role.findUnique({ where: { name: 'admin' } }),
   108→      this.prisma.role.findUnique({ where: { name: 'user' } }),
   109→    ]);
   110→
   111→    if (!adminRole || !userRole) {
   112→      // Roles should exist from seed - log warning but don't fail
   113→      console.warn('Roles not found in database. Run seed script: npm run prisma:seed');
   114→      return;
   115→    }
   116→
   117→    // Get existing user roles
