import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { JwtService } from '@nestjs/jwt';
import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';

export type OAuthUser = {
  email: string;
  providerId: string;
  provider?: string;          // 'google' (default), room for others later
  firstName?: string;
  lastName?: string;
  avatarUrl?: string | null;  // Google "picture"
  locale?: string | null;     // Google "locale"
  emailVerified?: boolean;    // Google "email_verified"
  hostedDomain?: string | null; // Google "hd" (if any)
};

export type TokenPayload = { sub: string; email: string; iat?: number; exp?: number };

@Injectable()
export class AuthService {
  constructor(
    private prisma: PrismaService,
    private jwt: JwtService,
    private auditLog: AuditLogService,
  ) {}

  /**
   * Upsert User, ensure Player exists, and persist OAuth profile fields.
   * Returns a minimal shape for token creation.
   */
  async validateOrCreateOAuthUser(o: OAuthUser): Promise<{ id: string; email: string }> {
    const email = o.email.toLowerCase();
    const firstName = o.firstName ?? 'Golfer';
    const lastName = o.lastName ?? 'User';
    const provider = o.provider ?? 'google';
    const now = new Date();

    const user = await this.prisma.user.upsert({
      where: { email },
      update: {
        provider,
        providerId: o.providerId,
        firstName,
        lastName,
        // only set when provided; undefined means "leave as-is" in Prisma
        avatarUrl: o.avatarUrl ?? undefined,
        locale: o.locale ?? undefined,
        emailVerified: o.emailVerified ?? undefined,
        hostedDomain: o.hostedDomain ?? undefined,
        lastLoginAt: now,
      },
      create: {
        email,
        provider,
        providerId: o.providerId,
        firstName,
        lastName,
        avatarUrl: o.avatarUrl ?? null,
        locale: o.locale ?? null,
        emailVerified: o.emailVerified ?? false,
        hostedDomain: o.hostedDomain ?? null,
        lastLoginAt: now,
        player: {
          create: {
            firstName,
            lastName,
          },
        },
      },
      include: { player: true },
    });

    // In case user existed but no Player row was ever created
    if (!user.player) {
      await this.prisma.player.create({
        data: {
          userId: user.id,
          firstName,
          lastName,
        },
      });
    }

    // Assign roles on first login or ensure they exist
    await this.ensureUserRoles(user.id, email);

    // Audit log: successful login
    await this.auditLog.log(user.id, AuditAction.LOGIN, 'Auth', {
      provider,
      email: user.email,
    });

    return { id: user.id, email: user.email };
  }

  /**
   * Ensure user has appropriate roles
   * - info@lazygolfing.com gets admin role
   * - All other users get user role
   */
  private async ensureUserRoles(userId: string, email: string): Promise<void> {
    const isAdmin = email.toLowerCase() === 'info@lazygolfing.com';

    // Get roles
    const [adminRole, userRole] = await Promise.all([
      this.prisma.role.findUnique({ where: { name: 'admin' } }),
      this.prisma.role.findUnique({ where: { name: 'user' } }),
    ]);

    if (!adminRole || !userRole) {
      // Roles should exist from seed - log warning but don't fail
      console.warn('Roles not found in database. Run seed script: npm run prisma:seed');
      return;
    }

    // Get existing user roles
    const existingRoles = await this.prisma.userRole.findMany({
      where: { userId },
      select: { roleId: true },
    });

    const existingRoleIds = new Set(existingRoles.map(r => r.roleId));

    // Assign admin role if user is admin and doesn't have it
    if (isAdmin && !existingRoleIds.has(adminRole.id)) {
      await this.prisma.userRole.create({
        data: {
          userId,
          roleId: adminRole.id,
        },
      });
    }

    // Always ensure user has the 'user' role
    if (!existingRoleIds.has(userRole.id)) {
      await this.prisma.userRole.create({
        data: {
          userId,
          roleId: userRole.id,
        },
      });
    }
  }

  /** Issue a JWT for the client (controller sets it as an HttpOnly cookie). */
  createToken(user: { id: string; email: string }): string {
    const payload: TokenPayload = { email: user.email, sub: user.id };
    return this.jwt.sign(payload);
  }

  /** Verify a JWT string and return typed payload (or null if invalid). */
  verifyToken(token: string): TokenPayload | null {
    try {
      return this.jwt.verify<TokenPayload>(token);
    } catch {
      return null;
    }
  }
}

