import { Body, Controller, Get, Put, Delete, UseGuards } from '@nestjs/common';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { CsrfGuard } from '../auth/csrf.guard';
import { ProfileService } from './profile.service';
import { RoundsService } from '../rounds/rounds.service';
import { UpdateProfileDto } from './update-profile.dto';
import { CurrentUser } from '../auth/current-user.decorator';
import type { AuthUser } from '../auth/current-user.decorator';


@Controller()
@UseGuards(JwtAuthGuard, CsrfGuard) // Apply JWT auth and CSRF protection to all routes
export class ProfileController {
  constructor(
    private svc: ProfileService,
    private roundsSvc: RoundsService,
  ) {}

  @Get('v1/me')
  async me(@CurrentUser() user: AuthUser) {
    return this.svc.getMe(user.userId);
  }

  // Primary save route used by the frontend
  @Put('v1/me')
  async updateMe(@CurrentUser() user: AuthUser, @Body() dto: UpdateProfileDto) {
    return this.svc.updateMe(user.userId, dto);
  }

  // Backward-compatible alias if you ever call /v1/profile
  @Put('v1/profile')
  async updateProfile(@CurrentUser() user: AuthUser, @Body() dto: UpdateProfileDto) {
    return this.svc.updateMe(user.userId, dto);
  }

  /**
   * Get user statistics (rounds, scores, etc.)
   */
  @Get('v1/me/stats')
  async getStats(@CurrentUser() user: AuthUser) {
    return this.svc.getStats(user.userId);
  }

  /**
   * Get all playing partners with statistics
   */
  @Get('v1/me/playing-partners')
  async getPlayingPartners(@CurrentUser() user: AuthUser) {
    return this.roundsSvc.getPlayingPartners(user.userId);
  }

  /**
   * Export all user data (GDPR compliance)
   */
  @Get('v1/me/export')
  async exportData(@CurrentUser() user: AuthUser) {
    return this.svc.exportUserData(user.userId);
  }

  /**
   * Delete account and all associated data (GDPR right to be forgotten)
   * WARNING: This is permanent and cannot be undone
   */
  @Delete('v1/me')
  async deleteAccount(@CurrentUser() user: AuthUser) {
    return this.svc.deleteUserAccount(user.userId);
  }
}

