   237→        player: {
   238→          include: {
   239→            rounds: {
   240→              where: { deletedAt: null }, // Only include active rounds
   241→              orderBy: { date: 'desc' },
   242→            },
   243→          },
   244→        },
   245→      },
   246→    });
   247→
   248→    if (!user) throw new NotFoundException('User not found');
   249→
   250→    // Audit log: data export
   251→    await this.auditLog.log(userId, AuditAction.DATA_EXPORTED, `User:${userId}`);
   252→
   253→    return {
   254→      user: {
   255→        id: user.id,
   256→        email: user.email,
   257→        firstName: user.firstName,
   258→        lastName: user.lastName,
   259→        avatarUrl: user.avatarUrl,
   260→        locale: user.locale,
   261→        emailVerified: user.emailVerified,
   262→        lastLoginAt: user.lastLoginAt,
   263→        createdAt: user.createdAt,
   264→        updatedAt: user.updatedAt,
   265→      },
   266→      player: user.player ? {
   267→        id: user.player.id,
   268→        firstName: user.player.firstName,
   269→        lastName: user.player.lastName,
   270→        ghinNumber: user.player.ghinNumber,
   271→        handicap: user.player.handicap,
   272→        createdAt: user.player.createdAt,
   273→      } : null,
   274→      rounds: user.player?.rounds || [],
   275→      exportedAt: new Date().toISOString(),
   276→    };
   277→  }
   278→
   279→  /**
   280→   * Delete user account and all associated data (GDPR right to be forgotten)
   281→   */
   282→  async deleteUserAccount(userId: string) {
   283→    const user = await this.prisma.user.findUnique({
   284→      where: { id: userId },
   285→      include: { player: true },
   286→    });
   287→
   288→    if (!user) throw new NotFoundException('User not found');
   289→
   290→    // Audit log: account deletion (before deleting)
   291→    await this.auditLog.log(userId, AuditAction.ACCOUNT_DELETED, `User:${userId}`, {
   292→      email: user.email,
   293→      deletedAt: new Date().toISOString(),
   294→    });
   295→
   296→    // Delete in transaction (cascade will handle rounds and audit logs)
   297→    await this.prisma.$transaction(async (tx) => {
   298→      // Delete player (will cascade to rounds if configured)
   299→      if (user.player) {
   300→        await tx.round.deleteMany({
   301→          where: { playerId: user.player.id },
   302→        });
   303→        await tx.player.delete({
   304→          where: { id: user.player.id },
   305→        });
   306→      }
   307→
   308→      // Delete audit logs for this user
   309→      await tx.auditLog.deleteMany({
   310→        where: { userId },
   311→      });
   312→
   313→      // Finally, delete the user
   314→      await tx.user.delete({
   315→        where: { id: userId },
   316→      });
   317→    });
   318→
   319→    return { deleted: true, userId };
   320→  }
   321→}
