import { Body, Controller, Get, Post, Put, Delete, Param, Query, Req, UseGuards, NotFoundException, BadRequestException, InternalServerErrorException, Logger } from '@nestjs/common';
import type { Request } from 'express';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { CsrfGuard } from '../auth/csrf.guard';
import { RoundsService } from './rounds.service';
import { CreateRoundDto } from './dto/create-round.dto';
import { UpdateRoundDto } from './dto/update-round.dto';
import { ImportCsvDto } from './dto/import-csv.dto';

@Controller('v1/rounds')
@UseGuards(JwtAuthGuard, CsrfGuard)
export class RoundsController {
  private readonly logger = new Logger(RoundsController.name);

  constructor(private svc: RoundsService) {}

  @Get()
  async list(
    @Req() req: Request,
    @Query('limit') limit?: string,
    @Query('sortBy') sortBy?: string,
    @Query('sortOrder') sortOrder?: string,
    @Query('search') search?: string,
  ) {
    const { userId } = (req as any).user;
    return this.svc.listByUser(userId, {
      limit: limit ? parseInt(limit, 10) : 20,
      sortBy: sortBy || 'date',
      sortOrder: sortOrder || 'desc',
      search: search || undefined,
    });
  }

  @Post()
  async create(@Req() req: Request, @Body() body: CreateRoundDto) {
    const { userId } = (req as any).user;

    try {
      this.logger.log(`Creating round for user ${userId}: ${body.courseName}, ${body.strokes} strokes`);

      // Validate date if provided
      if (body.date) {
        const parsedDate = new Date(body.date);
        if (isNaN(parsedDate.getTime())) {
          throw new BadRequestException('Invalid date format. Please use YYYY-MM-DD format.');
        }
      }

      const round = await this.svc.createForUser(userId, {
        courseId: body.courseId,
        courseName: body.courseName,
        strokes: Number(body.strokes),
        front9: body.front9,
        back9: body.back9,
        playingPartners: body.playingPartners,
        date: body.date,
        teeTime: body.teeTime,
        latitude: body.latitude,
        longitude: body.longitude,
        notes: body.notes,
      });

      this.logger.log(`Round created successfully: ${round.id}`);
      return round;

    } catch (error) {
      this.logger.error(`Failed to create round for user ${userId}`, error instanceof Error ? error.stack : String(error));

      if (error instanceof BadRequestException) {
        throw error;
      }

      // Handle specific error cases
      if (error instanceof Error) {
        if (error.message.includes('No player profile')) {
          throw new NotFoundException('Player profile not found. Please contact support.');
        }
        if (error.message.includes('Invalid date')) {
          throw new BadRequestException(error.message);
        }
        // Prisma validation errors
        if (error.message.includes('Argument') || error.message.includes('validation')) {
          throw new BadRequestException('Invalid round data provided.');
        }
      }

      // Generic fallback
      throw new InternalServerErrorException('Failed to create round. Please try again.');
    }
  }

  /**
   * Bulk import rounds from CSV
   */
  @Post('import-csv')
  async importCsv(@Req() req: Request, @Body() body: ImportCsvDto) {
    const { userId } = (req as any).user;

    try {
      this.logger.log(`Importing ${body.rounds.length} rounds for user ${userId}`);

      const results = {
        success: 0,
        failed: 0,
        errors: [] as string[],
      };

      for (const [index, roundData] of body.rounds.entries()) {
        try {
          await this.svc.createForUser(userId, {
            courseId: roundData.courseId,
            courseName: roundData.courseName,
            strokes: Number(roundData.strokes),
            front9: roundData.front9,
            back9: roundData.back9,
            date: roundData.date,
            notes: roundData.notes,
          });
          results.success++;
        } catch (error) {
          results.failed++;
          const errorMsg = error instanceof Error ? error.message : 'Unknown error';
          results.errors.push(`Row ${index + 1}: ${errorMsg}`);
          this.logger.warn(`Failed to import round at row ${index + 1}: ${errorMsg}`);
        }
      }

      this.logger.log(`Import complete: ${results.success} successful, ${results.failed} failed`);
      return results;

    } catch (error) {
      this.logger.error(`CSV import failed for user ${userId}`, error instanceof Error ? error.stack : String(error));
      throw new BadRequestException('Failed to process CSV import');
    }
  }

  @Put(':id')
  async update(
    @Req() req: Request,
    @Param('id') roundId: string,
    @Body() body: UpdateRoundDto
  ) {
    const { userId } = (req as any).user;
    try {
      return await this.svc.updateRound(userId, roundId, body);
    } catch (error) {
      throw new NotFoundException(error instanceof Error ? error.message : 'Round not found');
    }
  }

  @Delete(':id')
  async delete(@Req() req: Request, @Param('id') roundId: string) {
    const { userId } = (req as any).user;
    try {
      return await this.svc.softDeleteRound(userId, roundId);
    } catch (error) {
      throw new NotFoundException(error instanceof Error ? error.message : 'Round not found');
    }
  }

  /**
   * Get potential round matches for linking (based on tee time and/or GPS)
   */
  @Get(':id/suggestions')
  async getSuggestions(@Req() req: Request, @Param('id') roundId: string) {
    const { userId } = (req as any).user;
    try {
      return await this.svc.findPotentialMatches(roundId, userId);
    } catch (error) {
      throw new NotFoundException(error instanceof Error ? error.message : 'Round not found');
    }
  }

  /**
   * Link two rounds together (playing partners)
   */
  @Post(':id/link/:targetId')
  async linkRounds(
    @Req() req: Request,
    @Param('id') sourceRoundId: string,
    @Param('targetId') targetRoundId: string
  ) {
    const { userId } = (req as any).user;
    try {
      return await this.svc.linkRounds(userId, sourceRoundId, targetRoundId);
    } catch (error) {
      throw new BadRequestException(error instanceof Error ? error.message : 'Failed to link rounds');
    }
  }

  /**
   * Get linked rounds for a specific round
   */
  @Get(':id/linked')
  async getLinkedRounds(@Req() req: Request, @Param('id') roundId: string) {
    const { userId } = (req as any).user;
    try {
      return await this.svc.getLinkedRounds(roundId, userId);
    } catch (error) {
      throw new NotFoundException(error instanceof Error ? error.message : 'Round not found');
    }
  }
}

