   374→      const timeWindowStart = new Date(round.teeTime.getTime() - 30 * 60 * 1000);
   375→      const timeWindowEnd = new Date(round.teeTime.getTime() + 30 * 60 * 1000);
   376→
   377→      const timeMatches = await this.prisma.round.findMany({
   378→        where: {
   379→          id: { not: roundId }, // Exclude the source round
   380→          deletedAt: null,
   381→          playerId: { not: player.id }, // Exclude own rounds
   382→          ...(round.courseId ? { courseId: round.courseId } : { courseName: round.courseName }),
   383→          teeTime: {
   384→            gte: timeWindowStart,
   385→            lte: timeWindowEnd,
   386→          },
   387→        },
   388→        include: {
   389→          player: {
   390→            include: {
   391→              user: {
   392→                select: {
   393→                  id: true,
   394→                  email: true,
   395→                },
   396→              },
   397→            },
   398→          },
   399→        },
   400→        take: 10, // Limit results
   401→      });
   402→
   403→      matches.push(...timeMatches);
   404→    }
   405→
   406→    // GPS-based matching (within ~100 meters)
   407→    if (round.latitude && round.longitude) {
   408→      // Rough calculation: 1 degree ≈ 111km
   409→      // 100m ≈ 0.0009 degrees
   410→      const latDelta = 0.001; // ~111 meters
   411→      const lonDelta = 0.001;
   412→
   413→      const dateStart = new Date(round.date);
   414→      dateStart.setHours(0, 0, 0, 0);
   415→      const dateEnd = new Date(round.date);
   416→      dateEnd.setHours(23, 59, 59, 999);
