   418→      const gpsMatches = await this.prisma.round.findMany({
   419→        where: {
   420→          id: { not: roundId },
   421→          deletedAt: null,
   422→          playerId: { not: player.id },
   423→          latitude: {
   424→            gte: round.latitude - latDelta,
   425→            lte: round.latitude + latDelta,
   426→          },
   427→          longitude: {
   428→            gte: round.longitude - lonDelta,
   429→            lte: round.longitude + lonDelta,
   430→          },
   431→          date: {
   432→            gte: dateStart,
   433→            lte: dateEnd,
   434→          },
   435→        },
   436→        include: {
   437→          player: {
   438→            include: {
   439→              user: {
   440→                select: {
   441→                  id: true,
   442→                  email: true,
   443→                },
   444→              },
   445→            },
   446→          },
   447→        },
   448→        take: 10,
   449→      });
   450→
   451→      // Merge GPS matches with time matches (avoid duplicates)
   452→      const existingIds = new Set(matches.map(m => m.id));
