   456→        }
   457→      }
   458→    }
   459→
   460→    // Check for existing links to filter out already-linked rounds
   461→    const existingLinks = await this.prisma.roundLink.findMany({
   462→      where: {
   463→        OR: [
   464→          { sourceRoundId: roundId },
   465→          { targetRoundId: roundId },
   466→        ],
   467→      },
   468→    });
   469→
   470→    const linkedRoundIds = new Set(
   471→      existingLinks.flatMap(link => [link.sourceRoundId, link.targetRoundId])
   472→    );
   473→
   474→    // Filter out already-linked rounds
   475→    const filteredMatches = matches.filter(m => !linkedRoundIds.has(m.id));
   476→
   477→    return filteredMatches.map(match => ({
