import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';

@Injectable()
export class RoundsService {
  constructor(
    private prisma: PrismaService,
    private auditLog: AuditLogService,
  ) {}

  async listByUser(
    userId: string,
    options: {
      limit?: number;
      sortBy?: string;
      sortOrder?: string;
      search?: string;
    } = {}
  ) {
    const { limit = 20, sortBy = 'date', sortOrder = 'desc', search } = options;

    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) return [];

    const where: any = {
      playerId: player.id,
      deletedAt: null, // Only return non-deleted rounds
    };

    // Add search filter if provided
    if (search) {
      where.courseName = {
        contains: search,
        mode: 'insensitive',
      };
    }

    // Validate sort field
    const validSortFields = ['date', 'courseName', 'strokes', 'createdAt'];
    const orderByField = validSortFields.includes(sortBy) ? sortBy : 'date';
    const orderByDirection = sortOrder === 'asc' ? 'asc' : 'desc';

    const rounds = await this.prisma.round.findMany({
      where,
      orderBy: { [orderByField]: orderByDirection },
      take: Math.min(Math.max(limit, 1), 100),
      include: {
        course: {
          select: {
            id: true,
            name: true,
            city: true,
            state: true,
            totalPar: true,
          },
        },
      },
    });

    // Fetch linked partners for all rounds
    const roundIds = rounds.map(r => r.id);
    const links = await this.prisma.roundLink.findMany({
      where: {
        OR: [
          { sourceRoundId: { in: roundIds } },
          { targetRoundId: { in: roundIds } },
        ],
        status: { in: ['pending', 'confirmed'] },
      },
      include: {
        sourceRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    firstName: true,
                    lastName: true,
                  },
                },
              },
            },
          },
        },
        targetRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    firstName: true,
                    lastName: true,
                  },
                },
              },
            },
          },
        },
      },
    });

    // Build a map of roundId -> partners
    const partnersMap = new Map<string, any[]>();
    for (const link of links) {
      const isSourceMine = roundIds.includes(link.sourceRoundId);
      const myRoundId = isSourceMine ? link.sourceRoundId : link.targetRoundId;
      const partnerRound = isSourceMine ? link.targetRound : link.sourceRound;

      if (!partnersMap.has(myRoundId)) {
        partnersMap.set(myRoundId, []);
      }

      partnersMap.get(myRoundId)!.push({
        linkId: link.id,
        status: link.status,
        firstName: partnerRound.player.user.firstName,
        lastName: partnerRound.player.user.lastName,
        strokes: partnerRound.strokes,
      });
    }

    // Attach partners to each round
    const roundsWithPartners = rounds.map(round => ({
      ...round,
      linkedPartners: partnersMap.get(round.id) || [],
    }));

    // Audit log: rounds viewed
    await this.auditLog.log(userId, AuditAction.ROUND_VIEWED, `Rounds:${player.id}`, {
      count: rounds.length,
      filters: { search, sortBy: orderByField, sortOrder: orderByDirection },
    });

    return roundsWithPartners;
  }

  async createForUser(
    userId: string,
    data: {
      courseId?: string;
      courseName?: string;
      strokes: number;
      front9?: number;
      back9?: number;
      playingPartners?: string;
      date?: string;
      teeTime?: string;
      latitude?: number;
      longitude?: number;
      notes?: string;
      // Advanced stats
      girPct?: number;
      firPct?: number;
      approachPct?: number;
      front9Putts?: number;
      back9Putts?: number;
      totalPutts?: number;
      holeInOnes?: number;
      eagles?: number;
      birdies?: number;
      pars?: number;
      bogeys?: number;
      doubleBogeys?: number;
      triplePlusBogeys?: number;
    },
  ) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');
    const date = data.date ? new Date(data.date) : undefined;
    const teeTime = data.teeTime ? new Date(data.teeTime) : undefined;

    const round = await this.prisma.round.create({
      data: {
        playerId: player.id,
        courseId: data.courseId || null,
        courseName: data.courseName || null,
        strokes: data.strokes,
        ...(data.front9 !== undefined ? { front9: data.front9 } : {}),
        ...(data.back9 !== undefined ? { back9: data.back9 } : {}),
        ...(data.playingPartners ? { playingPartners: data.playingPartners } : {}),
        ...(data.latitude !== undefined ? { latitude: data.latitude } : {}),
        ...(data.longitude !== undefined ? { longitude: data.longitude } : {}),
        ...(data.notes ? { notes: data.notes } : {}),
        ...(date ? { date } : {}),
        ...(teeTime ? { teeTime } : {}),
        // Advanced stats
        ...(data.girPct !== undefined ? { girPct: data.girPct } : {}),
        ...(data.firPct !== undefined ? { firPct: data.firPct } : {}),
        ...(data.approachPct !== undefined ? { approachPct: data.approachPct } : {}),
        ...(data.front9Putts !== undefined ? { front9Putts: data.front9Putts } : {}),
        ...(data.back9Putts !== undefined ? { back9Putts: data.back9Putts } : {}),
        ...(data.totalPutts !== undefined ? { totalPutts: data.totalPutts } : {}),
        ...(data.holeInOnes !== undefined ? { holeInOnes: data.holeInOnes } : {}),
        ...(data.eagles !== undefined ? { eagles: data.eagles } : {}),
        ...(data.birdies !== undefined ? { birdies: data.birdies } : {}),
        ...(data.pars !== undefined ? { pars: data.pars } : {}),
        ...(data.bogeys !== undefined ? { bogeys: data.bogeys } : {}),
        ...(data.doubleBogeys !== undefined ? { doubleBogeys: data.doubleBogeys } : {}),
        ...(data.triplePlusBogeys !== undefined ? { triplePlusBogeys: data.triplePlusBogeys } : {}),
      },
    });

    // Audit log: round created
    await this.auditLog.log(userId, AuditAction.ROUND_CREATED, `Round:${round.id}`, {
      courseName: data.courseName,
      strokes: data.strokes,
    });

    return round;
  }

  /**
   * Update an existing round
   */
  async updateRound(
    userId: string,
    roundId: string,
    data: {
      courseId?: string;
      courseName?: string;
      strokes?: number;
      front9?: number;
      back9?: number;
      playingPartners?: string;
      date?: string;
      teeTime?: string;
      latitude?: number;
      longitude?: number;
      notes?: string;
      // Advanced stats
      girPct?: number;
      firPct?: number;
      approachPct?: number;
      front9Putts?: number;
      back9Putts?: number;
      totalPutts?: number;
      holeInOnes?: number;
      eagles?: number;
      birdies?: number;
      pars?: number;
      bogeys?: number;
      doubleBogeys?: number;
      triplePlusBogeys?: number;
    }
  ) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    // Ensure the round belongs to this user
    const existing = await this.prisma.round.findFirst({
      where: {
        id: roundId,
        playerId: player.id,
        deletedAt: null,
      },
    });

    if (!existing) {
      throw new Error('Round not found');
    }

    const updateData: any = {};
    if (data.courseId !== undefined) updateData.courseId = data.courseId;
    if (data.courseName !== undefined) updateData.courseName = data.courseName;
    if (data.strokes !== undefined) updateData.strokes = data.strokes;
    if (data.front9 !== undefined) updateData.front9 = data.front9;
    if (data.back9 !== undefined) updateData.back9 = data.back9;
    if (data.playingPartners !== undefined) updateData.playingPartners = data.playingPartners;
    if (data.date !== undefined) updateData.date = new Date(data.date);
    if (data.teeTime !== undefined) updateData.teeTime = new Date(data.teeTime);
    if (data.latitude !== undefined) updateData.latitude = data.latitude;
    if (data.longitude !== undefined) updateData.longitude = data.longitude;
    if (data.notes !== undefined) updateData.notes = data.notes;
    // Advanced stats
    if (data.girPct !== undefined) updateData.girPct = data.girPct;
    if (data.firPct !== undefined) updateData.firPct = data.firPct;
    if (data.approachPct !== undefined) updateData.approachPct = data.approachPct;
    if (data.front9Putts !== undefined) updateData.front9Putts = data.front9Putts;
    if (data.back9Putts !== undefined) updateData.back9Putts = data.back9Putts;
    if (data.totalPutts !== undefined) updateData.totalPutts = data.totalPutts;
    if (data.holeInOnes !== undefined) updateData.holeInOnes = data.holeInOnes;
    if (data.eagles !== undefined) updateData.eagles = data.eagles;
    if (data.birdies !== undefined) updateData.birdies = data.birdies;
    if (data.pars !== undefined) updateData.pars = data.pars;
    if (data.bogeys !== undefined) updateData.bogeys = data.bogeys;
    if (data.doubleBogeys !== undefined) updateData.doubleBogeys = data.doubleBogeys;
    if (data.triplePlusBogeys !== undefined) updateData.triplePlusBogeys = data.triplePlusBogeys;

    const updated = await this.prisma.round.update({
      where: { id: roundId },
      data: updateData,
    });

    // Audit log: round updated
    await this.auditLog.log(userId, AuditAction.ROUND_UPDATED, `Round:${roundId}`, {
      changes: updateData,
    });

    return updated;
  }

  /**
   * Soft delete a round (sets deletedAt timestamp)
   */
  async softDeleteRound(userId: string, roundId: string) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    // Ensure the round belongs to this user
    const round = await this.prisma.round.findFirst({
      where: {
        id: roundId,
        playerId: player.id,
        deletedAt: null, // Only allow deleting non-deleted rounds
      },
    });

    if (!round) {
      throw new Error('Round not found or already deleted');
    }

    const deleted = await this.prisma.round.update({
      where: { id: roundId },
      data: { deletedAt: new Date() },
    });

    // Audit log: round deleted
    await this.auditLog.log(userId, AuditAction.ROUND_DELETED, `Round:${roundId}`, {
      courseName: round.courseName,
      strokes: round.strokes,
    });

    return deleted;
  }

  /**
   * Find potential round matches for linking based on tee time and/or GPS coordinates
   * @param roundId - The round to find matches for
   * @param userId - User making the request (for permissions)
   * @returns Array of potential matching rounds with player info
   */
  async findPotentialMatches(roundId: string, userId: string) {
    // Get the round and verify ownership
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    const round = await this.prisma.round.findFirst({
      where: {
        id: roundId,
        playerId: player.id,
        deletedAt: null,
      },
    });

    if (!round) {
      throw new Error('Round not found');
    }

    // Can't match without course, date, and at least one of (teeTime or GPS)
    if (!round.courseId && !round.courseName) {
      return [];
    }
    if (!round.teeTime && (!round.latitude || !round.longitude)) {
      return [];
    }

    const matches = [];

    // Time-based matching (±30 minutes)
    if (round.teeTime) {
      const timeWindowStart = new Date(round.teeTime.getTime() - 30 * 60 * 1000);
      const timeWindowEnd = new Date(round.teeTime.getTime() + 30 * 60 * 1000);

      const timeMatches = await this.prisma.round.findMany({
        where: {
          id: { not: roundId }, // Exclude the source round
          deletedAt: null,
          playerId: { not: player.id }, // Exclude own rounds
          ...(round.courseId ? { courseId: round.courseId } : { courseName: round.courseName }),
          teeTime: {
            gte: timeWindowStart,
            lte: timeWindowEnd,
          },
        },
        include: {
          player: {
            include: {
              user: {
                select: {
                  id: true,
                  email: true,
                },
              },
            },
          },
        },
        take: 10, // Limit results
      });

      matches.push(...timeMatches);
    }

    // GPS-based matching (within ~100 meters)
    if (round.latitude && round.longitude) {
      // Rough calculation: 1 degree ≈ 111km
      // 100m ≈ 0.0009 degrees
      const latDelta = 0.001; // ~111 meters
      const lonDelta = 0.001;

      const dateStart = new Date(round.date);
      dateStart.setHours(0, 0, 0, 0);
      const dateEnd = new Date(round.date);
      dateEnd.setHours(23, 59, 59, 999);

      const gpsMatches = await this.prisma.round.findMany({
        where: {
          id: { not: roundId },
          deletedAt: null,
          playerId: { not: player.id },
          latitude: {
            gte: round.latitude - latDelta,
            lte: round.latitude + latDelta,
          },
          longitude: {
            gte: round.longitude - lonDelta,
            lte: round.longitude + lonDelta,
          },
          date: {
            gte: dateStart,
            lte: dateEnd,
          },
        },
        include: {
          player: {
            include: {
              user: {
                select: {
                  id: true,
                  email: true,
                },
              },
            },
          },
        },
        take: 10,
      });

      // Merge GPS matches with time matches (avoid duplicates)
      const existingIds = new Set(matches.map(m => m.id));
      for (const gpsMatch of gpsMatches) {
        if (!existingIds.has(gpsMatch.id)) {
          matches.push(gpsMatch);
        }
      }
    }

    // Check for existing links to filter out already-linked rounds
    const existingLinks = await this.prisma.roundLink.findMany({
      where: {
        OR: [
          { sourceRoundId: roundId },
          { targetRoundId: roundId },
        ],
      },
    });

    const linkedRoundIds = new Set(
      existingLinks.flatMap(link => [link.sourceRoundId, link.targetRoundId])
    );

    // Filter out already-linked rounds
    const filteredMatches = matches.filter(m => !linkedRoundIds.has(m.id));

    return filteredMatches.map(match => ({
      round: {
        id: match.id,
        courseName: match.courseName,
        date: match.date,
        teeTime: match.teeTime,
        strokes: match.strokes,
        front9: match.front9,
        back9: match.back9,
      },
      player: {
        firstName: match.player.firstName,
        lastName: match.player.lastName,
      },
      user: {
        id: match.player.user.id,
        email: match.player.user.email,
      },
    }));
  }

  /**
   * Create a link between two rounds
   */
  async linkRounds(userId: string, sourceRoundId: string, targetRoundId: string) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    // Verify the source round belongs to the user
    const sourceRound = await this.prisma.round.findFirst({
      where: {
        id: sourceRoundId,
        playerId: player.id,
        deletedAt: null,
      },
    });

    if (!sourceRound) {
      throw new Error('Source round not found');
    }

    // Verify the target round exists
    const targetRound = await this.prisma.round.findFirst({
      where: {
        id: targetRoundId,
        deletedAt: null,
      },
    });

    if (!targetRound) {
      throw new Error('Target round not found');
    }

    // Check if link already exists
    const existingLink = await this.prisma.roundLink.findFirst({
      where: {
        OR: [
          { sourceRoundId, targetRoundId },
          { sourceRoundId: targetRoundId, targetRoundId: sourceRoundId },
        ],
      },
    });

    if (existingLink) {
      // If it's pending, mark as confirmed
      if (existingLink.status === 'pending') {
        return this.prisma.roundLink.update({
          where: { id: existingLink.id },
          data: { status: 'confirmed' },
        });
      }
      return existingLink;
    }

    // Create new link
    const link = await this.prisma.roundLink.create({
      data: {
        sourceRoundId,
        targetRoundId,
        createdBy: userId,
        status: 'pending', // Other player needs to confirm
      },
    });

    // Audit log
    await this.auditLog.log(userId, AuditAction.ROUND_UPDATED, `RoundLink:${link.id}`, {
      sourceRoundId,
      targetRoundId,
      action: 'linked',
    });

    return link;
  }

  /**
   * Get linked rounds for a specific round
   */
  async getLinkedRounds(roundId: string, userId: string) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    const links = await this.prisma.roundLink.findMany({
      where: {
        OR: [
          { sourceRoundId: roundId },
          { targetRoundId: roundId },
        ],
        status: { in: ['pending', 'confirmed'] },
      },
      include: {
        sourceRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    email: true,
                  },
                },
              },
            },
          },
        },
        targetRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    email: true,
                  },
                },
              },
            },
          },
        },
      },
    });

    return links.map(link => {
      const linkedRound = link.sourceRoundId === roundId ? link.targetRound : link.sourceRound;
      return {
        linkId: link.id,
        status: link.status,
        round: {
          id: linkedRound.id,
          courseName: linkedRound.courseName,
          date: linkedRound.date,
          teeTime: linkedRound.teeTime,
          strokes: linkedRound.strokes,
          front9: linkedRound.front9,
          back9: linkedRound.back9,
        },
        player: {
          firstName: linkedRound.player.firstName,
          lastName: linkedRound.player.lastName,
        },
        user: {
          id: linkedRound.player.user.id,
          email: linkedRound.player.user.email,
        },
      };
    });
  }

  /**
   * Get all playing partners for a user with statistics
   */
  async getPlayingPartners(userId: string) {
    const player = await this.prisma.player.findUnique({ where: { userId } });
    if (!player) throw new Error('No player profile for user');

    // Get all rounds for this player
    const myRounds = await this.prisma.round.findMany({
      where: { playerId: player.id, deletedAt: null },
      select: { id: true },
    });

    const myRoundIds = myRounds.map(r => r.id);

    // Get all round links involving this player's rounds
    const links = await this.prisma.roundLink.findMany({
      where: {
        OR: [
          { sourceRoundId: { in: myRoundIds } },
          { targetRoundId: { in: myRoundIds } },
        ],
        status: { in: ['pending', 'confirmed'] },
      },
      include: {
        sourceRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    firstName: true,
                    lastName: true,
                    email: true,
                    avatarUrl: true,
                  },
                },
              },
            },
          },
        },
        targetRound: {
          include: {
            player: {
              include: {
                user: {
                  select: {
                    id: true,
                    firstName: true,
                    lastName: true,
                    email: true,
                    avatarUrl: true,
                  },
                },
              },
            },
          },
        },
      },
    });

    // Aggregate partners by player ID
    const partnerMap = new Map<string, {
      playerId: string;
      firstName: string;
      lastName: string;
      email: string;
      avatarUrl: string | null;
      roundsPlayed: number;
      lastPlayed: Date | null;
    }>();

    for (const link of links) {
      // Determine which round belongs to the partner
      const isSourceMine = myRoundIds.includes(link.sourceRoundId);
      const partnerRound = isSourceMine ? link.targetRound : link.sourceRound;
      const partnerPlayer = partnerRound.player;

      const partnerId = partnerPlayer.id;

      if (partnerMap.has(partnerId)) {
        const existing = partnerMap.get(partnerId)!;
        existing.roundsPlayed += 1;
        if (partnerRound.date > (existing.lastPlayed || new Date(0))) {
          existing.lastPlayed = partnerRound.date;
        }
      } else {
        partnerMap.set(partnerId, {
          playerId: partnerId,
          firstName: partnerPlayer.firstName,
          lastName: partnerPlayer.lastName,
          email: partnerPlayer.user.email,
          avatarUrl: partnerPlayer.user.avatarUrl,
          roundsPlayed: 1,
          lastPlayed: partnerRound.date,
        });
      }
    }

    // Convert to array and sort by rounds played (descending)
    return Array.from(partnerMap.values())
      .sort((a, b) => b.roundsPlayed - a.roundsPlayed);
  }
}

