import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  Req,
  UseGuards,
  Logger,
  BadRequestException,
  InternalServerErrorException,
} from '@nestjs/common';
import type { Request } from 'express';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { CsrfGuard } from '../auth/csrf.guard';
import { AdminGuard } from '../auth/admin.guard';
import { CoursesService } from './courses.service';
import { CreateCourseDto } from './dto/create-course.dto';
import { UpdateCourseDto } from './dto/update-course.dto';

@Controller('v1/courses')
export class CoursesController {
  private readonly logger = new Logger(CoursesController.name);

  constructor(private readonly svc: CoursesService) {}

  /**
   * Search courses (autocomplete) with optional API integration
   * GET /v1/courses/search?q=pebble&limit=10&includeApi=true
   */
  @Get('search')
  async search(
    @Query('q') query: string,
    @Query('limit') limit?: string,
    @Query('includeApi') includeApi?: string,
  ) {
    try {
      const parsedLimit = limit ? parseInt(limit, 10) : 10;
      const shouldIncludeApi = includeApi === 'true';

      if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
        throw new BadRequestException('Limit must be between 1 and 100');
      }

      this.logger.log(`Searching courses: query="${query}", limit=${parsedLimit}, includeApi=${shouldIncludeApi}`);

      if (shouldIncludeApi) {
        // Search both local DB and API
        const { local, api } = await this.svc.searchWithApi(query || '', shouldIncludeApi, parsedLimit);

        return {
          query: query || '',
          local: local.map((c: any) => ({ ...c, source: 'local' })),
          api: api,
          totalCount: local.length + api.length,
        };
      } else {
        // Search local DB only
        const results = await this.svc.search(query || '', parsedLimit);

        return {
          query: query || '',
          results,
          count: results.length,
        };
      }
    } catch (error) {
      this.logger.error(`Failed to search courses`, error instanceof Error ? error.stack : String(error));

      if (error instanceof BadRequestException) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to search courses');
    }
  }

  /**
   * Import a course from Golf API
   * POST /v1/courses/import
   */
  @Post('import')
  @UseGuards(JwtAuthGuard, CsrfGuard)
  async importFromApi(
    @Req() req: Request,
    @Body() body: { apiCourseId: number },
  ) {
    const { userId } = (req as any).user;

    try {
      if (!body.apiCourseId || typeof body.apiCourseId !== 'number') {
        throw new BadRequestException('apiCourseId must be a number');
      }

      this.logger.log(`Importing course from API: ${body.apiCourseId} (user: ${userId})`);

      const course = await this.svc.importCourseFromApi(body.apiCourseId, userId);

      this.logger.log(`Course imported successfully: ${course.id}`);

      return course;
    } catch (error) {
      this.logger.error(`Failed to import course`, error instanceof Error ? error.stack : String(error));

      if (error instanceof Error && error.name.includes('Exception')) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to import course');
    }
  }

  /**
   * Get nearby courses sorted by distance
   * GET /v1/courses/nearby?lat=43.1614&lon=-85.7100&limit=50
   */
  @Get('nearby')
  async getNearby(
    @Query('lat') lat?: string,
    @Query('lon') lon?: string,
    @Query('limit') limit?: string,
  ) {
    try {
      // Default to Sparta, Michigan if no coordinates provided
      const latitude = lat ? parseFloat(lat) : 43.1614;
      const longitude = lon ? parseFloat(lon) : -85.7100;
      const parsedLimit = limit ? parseInt(limit, 10) : 50;

      if (isNaN(latitude) || isNaN(longitude)) {
        throw new BadRequestException('Invalid latitude or longitude');
      }

      if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
        throw new BadRequestException('Limit must be between 1 and 100');
      }

      this.logger.log(`Getting nearby courses: lat=${latitude}, lon=${longitude}, limit=${parsedLimit}`);

      const courses = await this.svc.getNearby(latitude, longitude, parsedLimit);

      return courses;
    } catch (error) {
      this.logger.error(`Failed to get nearby courses`, error instanceof Error ? error.stack : String(error));

      if (error instanceof BadRequestException) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to get nearby courses');
    }
  }

  /**
   * Create a new course
   * POST /v1/courses
   */
  @Post()
  @UseGuards(JwtAuthGuard, CsrfGuard)
  async create(@Req() req: Request, @Body() dto: CreateCourseDto) {
    const { userId } = (req as any).user;

    try {
      this.logger.log(`Creating course: ${dto.name} (user: ${userId})`);

      const course = await this.svc.create(userId, dto);

      this.logger.log(`Course created successfully: ${course.id}`);

      return course;
    } catch (error) {
      this.logger.error(`Failed to create course`, error instanceof Error ? error.stack : String(error));

      // Re-throw known exceptions (ConflictException, BadRequestException, etc.)
      if (error instanceof Error && error.name.includes('Exception')) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to create course');
    }
  }

  /**
   * List all courses with pagination
   * GET /v1/courses?page=1&limit=50
   */
  @Get()
  async list(
    @Query('page') page?: string,
    @Query('limit') limit?: string,
  ) {
    try {
      const parsedPage = page ? parseInt(page, 10) : 1;
      const parsedLimit = limit ? parseInt(limit, 10) : 50;

      if (isNaN(parsedPage) || parsedPage < 1) {
        throw new BadRequestException('Page must be a positive integer');
      }

      if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
        throw new BadRequestException('Limit must be between 1 and 100');
      }

      this.logger.log(`Listing courses: page=${parsedPage}, limit=${parsedLimit}`);

      return await this.svc.list(parsedPage, parsedLimit);
    } catch (error) {
      this.logger.error(`Failed to list courses`, error instanceof Error ? error.stack : String(error));

      if (error instanceof BadRequestException) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to list courses');
    }
  }

  /**
   * Get course by ID with statistics
   * GET /v1/courses/:id
   */
  @Get(':id')
  async getById(@Param('id') id: string) {
    try {
      this.logger.log(`Getting course: ${id}`);

      return await this.svc.getById(id);
    } catch (error) {
      this.logger.error(`Failed to get course ${id}`, error instanceof Error ? error.stack : String(error));

      // Re-throw NotFoundException
      if (error instanceof Error && error.name === 'NotFoundException') {
        throw error;
      }

      throw new InternalServerErrorException('Failed to get course');
    }
  }

  /**
   * Update course details
   * PUT /v1/courses/:id
   * ADMIN ONLY
   */
  @Put(':id')
  @UseGuards(JwtAuthGuard, CsrfGuard, AdminGuard)
  async update(
    @Param('id') id: string,
    @Req() req: Request,
    @Body() dto: UpdateCourseDto,
  ) {
    const { userId } = (req as any).user;

    try {
      this.logger.log(`Updating course ${id} (user: ${userId})`);

      const updated = await this.svc.update(id, userId, dto);

      this.logger.log(`Course updated successfully: ${id}`);

      return updated;
    } catch (error) {
      this.logger.error(`Failed to update course ${id}`, error instanceof Error ? error.stack : String(error));

      // Re-throw known exceptions
      if (error instanceof Error && error.name.includes('Exception')) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to update course');
    }
  }

  /**
   * Delete a course
   * DELETE /v1/courses/:id
   * ADMIN ONLY
   */
  @Delete(':id')
  @UseGuards(JwtAuthGuard, CsrfGuard, AdminGuard)
  async delete(@Param('id') id: string, @Req() req: Request) {
    const { userId } = (req as any).user;

    try {
      this.logger.log(`Deleting course ${id} (user: ${userId})`);

      const result = await this.svc.delete(id, userId);

      this.logger.log(`Course deleted successfully: ${id}`);

      return result;
    } catch (error) {
      this.logger.error(`Failed to delete course ${id}`, error instanceof Error ? error.stack : String(error));

      // Re-throw known exceptions
      if (error instanceof Error && error.name.includes('Exception')) {
        throw error;
      }

      throw new InternalServerErrorException('Failed to delete course');
    }
  }
}

