    63→
    64→  /**
    65→   * Get most popular courses (by number of rounds played)
    66→   */
    67→  async getMostPopular(limit: number = 10) {
    68→    const courses = await this.prisma.course.findMany({
    69→      include: {
    70→        _count: {
    71→          select: { rounds: true },
    72→        },
    73→      },
    74→      take: limit,
    75→      orderBy: {
    76→        rounds: {
    77→          _count: 'desc',
    78→        },
    79→      },
    80→    });
    81→
    82→    return courses.map(course => ({
    83→      id: course.id,
    84→      name: course.name,
    85→      city: course.city,
    86→      state: course.state,
    87→      country: course.country,
    88→      totalPar: course.totalPar,
    89→      courseRating: course.courseRating,
    90→      slopeRating: course.slopeRating,
    91→      timesPlayed: course._count.rounds,
    92→    }));
    93→  }
    94→
    95→  /**
    96→   * Create a new course
    97→   * Normalizes name to title case and checks for duplicates
    98→   */
    99→  async create(
   100→    userId: string,
   101→    data: {
   102→      name: string;
   103→      city?: string;
   104→      state?: string;
   105→      country?: string;
   106→      totalPar?: number;
   107→      courseRating?: number;
   108→      slopeRating?: number;
   109→    },
   110→  ) {
   111→    // Normalize name to title case
   112→    const normalizedName = this.normalizeName(data.name);
   113→
   114→    // Check if course already exists (case-insensitive)
   115→    const existing = await this.prisma.course.findFirst({
   116→      where: {
   117→        name: {
   118→          equals: normalizedName,
   119→          mode: 'insensitive',
   120→        },
   121→      },
   122→    });
   123→
   124→    if (existing) {
   125→      throw new ConflictException(
   126→        `Course "${existing.name}" already exists. Please select it from the list.`,
   127→      );
   128→    }
   129→
   130→    // Create the course
   131→    const course = await this.prisma.course.create({
   132→      data: {
   133→        name: normalizedName,
   134→        city: data.city?.trim() || null,
   135→        state: data.state?.trim() || null,
   136→        country: data.country?.trim() || null,
   137→        totalPar: data.totalPar || null,
   138→        courseRating: data.courseRating || null,
   139→        slopeRating: data.slopeRating || null,
   140→      },
   141→    });
   142→
   143→    // Audit log: course created
   144→    await this.auditLog.log(userId, AuditAction.COURSE_CREATED, `Course:${course.id}`, {
   145→      courseName: course.name,
   146→    });
   147→
   148→    return course;
   149→  }
   150→
   151→  /**
   152→   * Get all courses with pagination
   153→   */
   154→  async list(page: number = 1, limit: number = 50) {
   155→    const skip = (page - 1) * limit;
   156→    const take = Math.min(limit, 100); // Max 100 per page
   157→
   158→    const [courses, total] = await Promise.all([
   159→      this.prisma.course.findMany({
   160→        skip,
   161→        take,
   162→        include: {
   163→          _count: {
   164→            select: { rounds: true },
   165→          },
   166→        },
   167→        orderBy: {
   168→          name: 'asc',
   169→        },
   170→      }),
   171→      this.prisma.course.count(),
   172→    ]);
   173→
   174→    return {
   175→      data: courses.map(course => ({
   176→        id: course.id,
   177→        name: course.name,
   178→        city: course.city,
   179→        state: course.state,
   180→        country: course.country,
   181→        totalPar: course.totalPar,
   182→        courseRating: course.courseRating,
   183→        slopeRating: course.slopeRating,
   184→        timesPlayed: course._count.rounds,
   185→      })),
   186→      meta: {
   187→        total,
   188→        page,
   189→        limit: take,
   190→        totalPages: Math.ceil(total / take),
   191→      },
   192→    };
   193→  }
   194→
   195→  /**
   196→   * Get course by ID with statistics
   197→   */
   198→  async getById(courseId: string) {
   199→    const course = await this.prisma.course.findUnique({
   200→      where: { id: courseId },
   201→      include: {
   202→        _count: {
   203→          select: { rounds: true },
   204→        },
   205→        rounds: {
   206→          where: { deletedAt: null },
   207→          select: {
   208→            strokes: true,
   209→            date: true,
   210→            player: {
   211→              select: {
   212→                firstName: true,
   213→                lastName: true,
   214→              },
   215→            },
   216→          },
   217→          orderBy: { date: 'desc' },
   218→          take: 10, // Recent 10 rounds
   219→        },
   220→      },
   221→    });
   222→
   223→    if (!course) {
   224→      throw new NotFoundException('Course not found');
   225→    }
   226→
   227→    // Calculate statistics
   228→    const scores = course.rounds.map(r => r.strokes);
   229→    const stats = scores.length > 0 ? {
   230→      averageScore: Math.round(scores.reduce((a, b) => a + b, 0) / scores.length),
   231→      bestScore: Math.min(...scores),
   232→      worstScore: Math.max(...scores),
   233→    } : null;
   234→
   235→    return {
   236→      id: course.id,
   237→      name: course.name,
   238→      city: course.city,
   239→      state: course.state,
   240→      country: course.country,
   241→      totalPar: course.totalPar,
   242→      courseRating: course.courseRating,
   243→      slopeRating: course.slopeRating,
   244→      timesPlayed: course._count.rounds,
   245→      statistics: stats,
   246→      recentRounds: course.rounds,
   247→    };
   248→  }
   249→
   250→  /**
   251→   * Update course details (admin only)
   252→   */
   253→  async update(
   254→    courseId: string,
   255→    userId: string,
   256→    data: {
   257→      name?: string;
   258→      city?: string;
   259→      state?: string;
   260→      country?: string;
   261→      totalPar?: number;
   262→      courseRating?: number;
   263→      slopeRating?: number;
   264→    },
   265→  ) {
   266→    const course = await this.prisma.course.findUnique({
   267→      where: { id: courseId },
   268→    });
   269→
   270→    if (!course) {
   271→      throw new NotFoundException('Course not found');
   272→    }
   273→
   274→    // If name is being updated, normalize and check for duplicates
   275→    let normalizedName = course.name;
   276→    if (data.name && data.name !== course.name) {
   277→      normalizedName = this.normalizeName(data.name);
   278→
   279→      const existing = await this.prisma.course.findFirst({
   280→        where: {
   281→          name: {
   282→            equals: normalizedName,
   283→            mode: 'insensitive',
   284→          },
   285→          id: {
   286→            not: courseId, // Exclude current course
   287→          },
   288→        },
   289→      });
   290→
   291→      if (existing) {
   292→        throw new ConflictException(
   293→          `Course "${existing.name}" already exists. Cannot rename to that name.`,
   294→        );
   295→      }
   296→    }
   297→
   298→    const updated = await this.prisma.course.update({
   299→      where: { id: courseId },
   300→      data: {
   301→        name: data.name ? normalizedName : undefined,
   302→        city: data.city !== undefined ? data.city?.trim() || null : undefined,
   303→        state: data.state !== undefined ? data.state?.trim() || null : undefined,
   304→        country: data.country !== undefined ? data.country?.trim() || null : undefined,
   305→        totalPar: data.totalPar !== undefined ? data.totalPar : undefined,
   306→        courseRating: data.courseRating !== undefined ? data.courseRating : undefined,
   307→        slopeRating: data.slopeRating !== undefined ? data.slopeRating : undefined,
   308→      },
   309→    });
   310→
   311→    // Audit log: course updated
   312→    await this.auditLog.log(userId, AuditAction.COURSE_UPDATED, `Course:${courseId}`, {
   313→      changes: data,
   314→    });
   315→
   316→    return updated;
   317→  }
   318→
   319→  /**
   320→   * Delete a course (admin only)
   321→   * This will set courseId to null on all related rounds
   322→   */
   323→  async delete(courseId: string, userId: string) {
   324→    const course = await this.prisma.course.findUnique({
   325→      where: { id: courseId },
   326→      include: {
   327→        _count: {
   328→          select: { rounds: true },
   329→        },
   330→      },
   331→    });
   332→
   333→    if (!course) {
   334→      throw new NotFoundException('Course not found');
   335→    }
   336→
   337→    // Audit log: course deleted
   338→    await this.auditLog.log(userId, AuditAction.COURSE_DELETED, `Course:${courseId}`, {
   339→      courseName: course.name,
   340→      affectedRounds: course._count.rounds,
   341→    });
   342→
   343→    // Delete the course (rounds will have courseId set to null due to ON DELETE SET NULL)
   344→    await this.prisma.course.delete({
   345→      where: { id: courseId },
   346→    });
   347→
   348→    return { deleted: true, courseId, affectedRounds: course._count.rounds };
   349→  }
   350→
   351→  /**
   352→   * Fetch courses from Golf Course API
   353→   * API returns 20 courses per page with full details
   354→   */
   355→  async fetchCoursesFromApi(page: number = 1): Promise<any[]> {
   356→    const apiKey = process.env.GOLF_API_KEY;
   357→    if (!apiKey) {
   358→      throw new Error('GOLF_API_KEY not configured');
   359→    }
   360→
   361→    const url = `https://api.golfcourseapi.com/v1/courses?page=${page}`;
   362→
   363→    try {
   364→      const response = await fetch(url, {
   365→        headers: {
   366→          'Authorization': `Key ${apiKey}`,
   367→          'Accept': 'application/json',
   368→        },
   369→      });
   370→
   371→      if (!response.ok) {
   372→        throw new Error(`Golf API request failed: ${response.status}`);
   373→      }
   374→
   375→      const data = await response.json();
   376→      return data.courses || [];
   377→    } catch (error) {
   378→      console.error('Error fetching from Golf API:', error);
   379→      throw error;
   380→    }
   381→  }
   382→
   383→  /**
   384→   * Transform Golf API course data to our Prisma schema
   385→   */
   386→  private transformApiCourse(apiCourse: any) {
   387→    // Get primary tee (prefer male Blue, fallback to first available)
   388→    const primaryTee =
   389→      apiCourse.tees?.male?.find((t: any) => t.tee_name === 'Blue') ||
   390→      apiCourse.tees?.male?.[0] ||
   391→      apiCourse.tees?.female?.[0];
   392→
   393→    // Calculate front/back 9 par from holes array
   394→    let front9Par: number | null = null;
   395→    let back9Par: number | null = null;
   396→
   397→    if (primaryTee?.holes && primaryTee.holes.length >= 18) {
   398→      front9Par = primaryTee.holes.slice(0, 9).reduce((sum: number, h: any) => sum + (h.par || 0), 0);
   399→      back9Par = primaryTee.holes.slice(9, 18).reduce((sum: number, h: any) => sum + (h.par || 0), 0);
   400→    }
   401→
   402→    return {
   403→      apiCourseId: apiCourse.id,
   404→      name: apiCourse.course_name || apiCourse.club_name,
   405→      city: apiCourse.location?.city || null,
   406→      state: apiCourse.location?.state || null,
   407→      country: apiCourse.location?.country || null,
   408→      zipCode: null, // Not provided by API
   409→      latitude: apiCourse.location?.latitude || null,
   410→      longitude: apiCourse.location?.longitude || null,
   411→      totalPar: primaryTee?.par_total || null,
   412→      front9Par: front9Par,
   413→      back9Par: back9Par,
   414→      courseRating: primaryTee?.course_rating || null,
   415→      slopeRating: primaryTee?.slope_rating || null,
   416→      apiData: apiCourse, // Store complete API response
   417→      lastSynced: new Date(),
   418→    };
   419→  }
   420→
   421→  /**
   422→   * Import a course from Golf API by API course ID
   423→   */
   424→  async importCourseFromApi(apiCourseId: number, userId: string) {
   425→    // Check if already imported
   426→    const existing = await this.prisma.course.findFirst({
   427→      where: { apiCourseId },
   428→    });
   429→
   430→    if (existing) {
   431→      return existing; // Already imported, return existing
   432→    }
   433→
   434→    // Fetch all courses until we find the one with this ID
   435→    // Note: API doesn't support single course lookup, so we page through
   436→    let page = 1;
   437→    let found = null;
   438→
   439→    while (page <= 10 && !found) { // Safety limit: 10 pages = 200 courses
   440→      const courses = await this.fetchCoursesFromApi(page);
   441→      found = courses.find((c: any) => c.id === apiCourseId);
   442→
   443→      if (!found && courses.length === 0) break; // No more courses
   444→      page++;
   445→    }
   446→
   447→    if (!found) {
   448→      throw new NotFoundException(`Course ${apiCourseId} not found in Golf API`);
   449→    }
   450→
   451→    // Transform and create course
   452→    const courseData = this.transformApiCourse(found);
   453→    const course = await this.prisma.course.create({
   454→      data: courseData,
   455→    });
   456→
   457→    // Audit log
   458→    await this.auditLog.log(userId, AuditAction.COURSE_CREATED, `Course:${course.id}`, {
   459→      courseName: course.name,
   460→      source: 'golf-api',
   461→      apiCourseId,
   462→    });
   463→
   464→    return course;
   465→  }
   466→
   467→  /**
   468→   * Search courses in both local DB and optionally Golf API
   469→   */
   470→  async searchWithApi(query: string, includeApi: boolean = false, limit: number = 10) {
   471→    // First, search local database
   472→    const localResults = await this.search(query, limit);
   473→
   474→    if (!includeApi || !query || query.trim().length === 0) {
   475→      return {
   476→        local: localResults,
   477→        api: [],
   478→      };
   479→    }
   480→
   481→    // Fetch from API and filter client-side (API doesn't support search)
   482→    try {
   483→      const apiCourses = await this.fetchCoursesFromApi(1); // Get first page
   484→      const normalizedQuery = query.trim().toLowerCase();
   485→
   486→      // Filter API courses by name match
   487→      const apiMatches = apiCourses
   488→        .filter((c: any) => {
   489→          const courseName = (c.course_name || c.club_name || '').toLowerCase();
   490→          return courseName.includes(normalizedQuery);
   491→        })
   492→        .slice(0, limit)
   493→        .map((c: any) => ({
   494→          apiCourseId: c.id,
   495→          name: c.course_name || c.club_name,
   496→          city: c.location?.city,
   497→          state: c.location?.state,
   498→          country: c.location?.country,
   499→          totalPar: c.tees?.male?.[0]?.par_total || null,
   500→          source: 'api' as const,
   501→        }));
   502→
   503→      // Filter out API results that are already in local DB
   504→      const localApiIds = new Set(
   505→        localResults
   506→          .filter((c: any) => c.apiCourseId)
   507→          .map((c: any) => c.apiCourseId)
   508→      );
   509→
   510→      const uniqueApiMatches = apiMatches.filter(
   511→        (c: any) => !localApiIds.has(c.apiCourseId)
   512→      );
   513→
   514→      return {
   515→        local: localResults,
   516→        api: uniqueApiMatches,
   517→      };
   518→    } catch (error) {
   519→      console.error('Error searching Golf API:', error);
   520→      // Fallback to local results only
   521→      return {
   522→        local: localResults,
   523→        api: [],
   524→      };
   525→    }
   526→  }
   527→
   528→  /**
   529→   * Get nearby courses sorted by distance
   530→   * Uses Haversine formula to calculate distances
   531→   */
   532→  async getNearby(latitude: number, longitude: number, limit: number = 50) {
   533→    // Get all courses with valid coordinates
   534→    const courses = await this.prisma.course.findMany({
   535→      where: {
   536→        latitude: { not: null },
   537→        longitude: { not: null },
   538→      },
   539→      include: {
   540→        _count: {
   541→          select: { rounds: true },
   542→        },
   543→      },
   544→    });
   545→
   546→    // Calculate distance for each course
   547→    const coursesWithDistance = courses.map(course => {
   548→      const distance = this.calculateDistance(
   549→        latitude,
   550→        longitude,
   551→        course.latitude!,
   552→        course.longitude!
   553→      );
   554→
   555→      return {
   556→        id: course.id,
   557→        name: course.name,
   558→        city: course.city,
   559→        state: course.state,
   560→        country: course.country,
   561→        latitude: course.latitude,
   562→        longitude: course.longitude,
   563→        totalPar: course.totalPar,
   564→        courseRating: course.courseRating,
   565→        slopeRating: course.slopeRating,
   566→        timesPlayed: course._count.rounds,
   567→        distanceMiles: Math.round(distance * 10) / 10, // Round to 1 decimal
   568→      };
   569→    });
   570→
   571→    // Sort by distance and return top N
   572→    return coursesWithDistance
   573→      .sort((a, b) => a.distanceMiles - b.distanceMiles)
   574→      .slice(0, limit);
   575→  }
   576→
   577→  /**
   578→   * Calculate distance between two coordinates using Haversine formula
   579→   * Returns distance in miles
   580→   */
   581→  private calculateDistance(
   582→    lat1: number,
   583→    lon1: number,
   584→    lat2: number,
   585→    lon2: number
   586→  ): number {
   587→    const R = 3959; // Earth's radius in miles
   588→    const dLat = this.toRad(lat2 - lat1);
   589→    const dLon = this.toRad(lon2 - lon1);
   590→
   591→    const a =
   592→      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
   593→      Math.cos(this.toRad(lat1)) *
   594→        Math.cos(this.toRad(lat2)) *
   595→        Math.sin(dLon / 2) *
   596→        Math.sin(dLon / 2);
   597→
   598→    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
   599→    return R * c;
   600→  }
   601→
   602→  /**
   603→   * Convert degrees to radians
   604→   */
   605→  private toRad(degrees: number): number {
   606→    return (degrees * Math.PI) / 180;
   607→  }
   608→
   609→  /**
   610→   * Normalize course name to title case
   611→   * Example: "pebble beach" -> "Pebble Beach"
   612→   */
   613→  private normalizeName(name: string): string {
   614→    return name
   615→      .trim()
   616→      .toLowerCase()
   617→      .split(' ')
   618→      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
   619→      .join(' ');
   620→  }
   621→}
