import { Injectable, ConflictException, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';

@Injectable()
export class CoursesService {
  constructor(
    private prisma: PrismaService,
    private auditLog: AuditLogService,
  ) {}

  /**
   * Search courses by name (fuzzy matching, case-insensitive)
   * Used for autocomplete functionality
   */
  async search(query: string, limit: number = 10) {
    if (!query || query.trim().length === 0) {
      // If no query, return most popular courses
      return this.getMostPopular(limit);
    }

    const normalizedQuery = query.trim().toLowerCase();

    // Find courses that match the query (case-insensitive partial match)
    const courses = await this.prisma.course.findMany({
      where: {
        name: {
          contains: normalizedQuery,
          mode: 'insensitive',
        },
      },
      include: {
        _count: {
          select: { rounds: true },
        },
      },
      take: limit,
      orderBy: [
        {
          rounds: {
            _count: 'desc', // Most played courses first
          },
        },
        {
          name: 'asc', // Then alphabetically
        },
      ],
    });

    // Format response with play counts
    return courses.map(course => ({
      id: course.id,
      name: course.name,
      city: course.city,
      state: course.state,
      country: course.country,
      totalPar: course.totalPar,
      courseRating: course.courseRating,
      slopeRating: course.slopeRating,
      timesPlayed: course._count.rounds,
    }));
  }

  /**
   * Get most popular courses (by number of rounds played)
   */
  async getMostPopular(limit: number = 10) {
    const courses = await this.prisma.course.findMany({
      include: {
        _count: {
          select: { rounds: true },
        },
      },
      take: limit,
      orderBy: {
        rounds: {
          _count: 'desc',
        },
      },
    });

    return courses.map(course => ({
      id: course.id,
      name: course.name,
      city: course.city,
      state: course.state,
      country: course.country,
      totalPar: course.totalPar,
      courseRating: course.courseRating,
      slopeRating: course.slopeRating,
      timesPlayed: course._count.rounds,
    }));
  }

  /**
   * Create a new course
   * Normalizes name to title case and checks for duplicates
   */
  async create(
    userId: string,
    data: {
      name: string;
      city?: string;
      state?: string;
      country?: string;
      totalPar?: number;
      courseRating?: number;
      slopeRating?: number;
    },
  ) {
    // Normalize name to title case
    const normalizedName = this.normalizeName(data.name);

    // Check if course already exists (case-insensitive)
    const existing = await this.prisma.course.findFirst({
      where: {
        name: {
          equals: normalizedName,
          mode: 'insensitive',
        },
      },
    });

    if (existing) {
      throw new ConflictException(
        `Course "${existing.name}" already exists. Please select it from the list.`,
      );
    }

    // Create the course
    const course = await this.prisma.course.create({
      data: {
        name: normalizedName,
        city: data.city?.trim() || null,
        state: data.state?.trim() || null,
        country: data.country?.trim() || null,
        totalPar: data.totalPar || null,
        courseRating: data.courseRating || null,
        slopeRating: data.slopeRating || null,
      },
    });

    // Audit log: course created
    await this.auditLog.log(userId, AuditAction.COURSE_CREATED, `Course:${course.id}`, {
      courseName: course.name,
    });

    return course;
  }

  /**
   * Get all courses with pagination
   */
  async list(page: number = 1, limit: number = 50) {
    const skip = (page - 1) * limit;
    const take = Math.min(limit, 100); // Max 100 per page

    const [courses, total] = await Promise.all([
      this.prisma.course.findMany({
        skip,
        take,
        include: {
          _count: {
            select: { rounds: true },
          },
        },
        orderBy: {
          name: 'asc',
        },
      }),
      this.prisma.course.count(),
    ]);

    return {
      data: courses.map(course => ({
        id: course.id,
        name: course.name,
        city: course.city,
        state: course.state,
        country: course.country,
        totalPar: course.totalPar,
        courseRating: course.courseRating,
        slopeRating: course.slopeRating,
        timesPlayed: course._count.rounds,
      })),
      meta: {
        total,
        page,
        limit: take,
        totalPages: Math.ceil(total / take),
      },
    };
  }

  /**
   * Get course by ID with statistics
   */
  async getById(courseId: string) {
    const course = await this.prisma.course.findUnique({
      where: { id: courseId },
      include: {
        _count: {
          select: { rounds: true },
        },
        rounds: {
          where: { deletedAt: null },
          select: {
            strokes: true,
            date: true,
            player: {
              select: {
                firstName: true,
                lastName: true,
              },
            },
          },
          orderBy: { date: 'desc' },
          take: 10, // Recent 10 rounds
        },
      },
    });

    if (!course) {
      throw new NotFoundException('Course not found');
    }

    // Calculate statistics
    const scores = course.rounds.map(r => r.strokes);
    const stats = scores.length > 0 ? {
      averageScore: Math.round(scores.reduce((a, b) => a + b, 0) / scores.length),
      bestScore: Math.min(...scores),
      worstScore: Math.max(...scores),
    } : null;

    return {
      id: course.id,
      name: course.name,
      city: course.city,
      state: course.state,
      country: course.country,
      totalPar: course.totalPar,
      courseRating: course.courseRating,
      slopeRating: course.slopeRating,
      timesPlayed: course._count.rounds,
      statistics: stats,
      recentRounds: course.rounds,
    };
  }

  /**
   * Update course details (admin only)
   */
  async update(
    courseId: string,
    userId: string,
    data: {
      name?: string;
      city?: string;
      state?: string;
      country?: string;
      totalPar?: number;
      courseRating?: number;
      slopeRating?: number;
    },
  ) {
    const course = await this.prisma.course.findUnique({
      where: { id: courseId },
    });

    if (!course) {
      throw new NotFoundException('Course not found');
    }

    // If name is being updated, normalize and check for duplicates
    let normalizedName = course.name;
    if (data.name && data.name !== course.name) {
      normalizedName = this.normalizeName(data.name);

      const existing = await this.prisma.course.findFirst({
        where: {
          name: {
            equals: normalizedName,
            mode: 'insensitive',
          },
          id: {
            not: courseId, // Exclude current course
          },
        },
      });

      if (existing) {
        throw new ConflictException(
          `Course "${existing.name}" already exists. Cannot rename to that name.`,
        );
      }
    }

    const updated = await this.prisma.course.update({
      where: { id: courseId },
      data: {
        name: data.name ? normalizedName : undefined,
        city: data.city !== undefined ? data.city?.trim() || null : undefined,
        state: data.state !== undefined ? data.state?.trim() || null : undefined,
        country: data.country !== undefined ? data.country?.trim() || null : undefined,
        totalPar: data.totalPar !== undefined ? data.totalPar : undefined,
        courseRating: data.courseRating !== undefined ? data.courseRating : undefined,
        slopeRating: data.slopeRating !== undefined ? data.slopeRating : undefined,
      },
    });

    // Audit log: course updated
    await this.auditLog.log(userId, AuditAction.COURSE_UPDATED, `Course:${courseId}`, {
      changes: data,
    });

    return updated;
  }

  /**
   * Delete a course (admin only)
   * This will set courseId to null on all related rounds
   */
  async delete(courseId: string, userId: string) {
    const course = await this.prisma.course.findUnique({
      where: { id: courseId },
      include: {
        _count: {
          select: { rounds: true },
        },
      },
    });

    if (!course) {
      throw new NotFoundException('Course not found');
    }

    // Audit log: course deleted
    await this.auditLog.log(userId, AuditAction.COURSE_DELETED, `Course:${courseId}`, {
      courseName: course.name,
      affectedRounds: course._count.rounds,
    });

    // Delete the course (rounds will have courseId set to null due to ON DELETE SET NULL)
    await this.prisma.course.delete({
      where: { id: courseId },
    });

    return { deleted: true, courseId, affectedRounds: course._count.rounds };
  }

  /**
   * Fetch courses from Golf Course API
   * API returns 20 courses per page with full details
   */
  async fetchCoursesFromApi(page: number = 1): Promise<any[]> {
    const apiKey = process.env.GOLF_API_KEY;
    if (!apiKey) {
      throw new Error('GOLF_API_KEY not configured');
    }

    const url = `https://api.golfcourseapi.com/v1/courses?page=${page}`;

    try {
      const response = await fetch(url, {
        headers: {
          'Authorization': `Key ${apiKey}`,
          'Accept': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`Golf API request failed: ${response.status}`);
      }

      const data = await response.json();
      return data.courses || [];
    } catch (error) {
      console.error('Error fetching from Golf API:', error);
      throw error;
    }
  }

  /**
   * Transform Golf API course data to our Prisma schema
   */
  private transformApiCourse(apiCourse: any) {
    // Get primary tee (prefer male Blue, fallback to first available)
    const primaryTee =
      apiCourse.tees?.male?.find((t: any) => t.tee_name === 'Blue') ||
      apiCourse.tees?.male?.[0] ||
      apiCourse.tees?.female?.[0];

    // Calculate front/back 9 par from holes array
    let front9Par: number | null = null;
    let back9Par: number | null = null;

    if (primaryTee?.holes && primaryTee.holes.length >= 18) {
      front9Par = primaryTee.holes.slice(0, 9).reduce((sum: number, h: any) => sum + (h.par || 0), 0);
      back9Par = primaryTee.holes.slice(9, 18).reduce((sum: number, h: any) => sum + (h.par || 0), 0);
    }

    return {
      apiCourseId: apiCourse.id,
      name: apiCourse.course_name || apiCourse.club_name,
      city: apiCourse.location?.city || null,
      state: apiCourse.location?.state || null,
      country: apiCourse.location?.country || null,
      zipCode: null, // Not provided by API
      latitude: apiCourse.location?.latitude || null,
      longitude: apiCourse.location?.longitude || null,
      totalPar: primaryTee?.par_total || null,
      front9Par: front9Par,
      back9Par: back9Par,
      courseRating: primaryTee?.course_rating || null,
      slopeRating: primaryTee?.slope_rating || null,
      apiData: apiCourse, // Store complete API response
      lastSynced: new Date(),
    };
  }

  /**
   * Import a course from Golf API by API course ID
   */
  async importCourseFromApi(apiCourseId: number, userId: string) {
    // Check if already imported
    const existing = await this.prisma.course.findFirst({
      where: { apiCourseId },
    });

    if (existing) {
      return existing; // Already imported, return existing
    }

    // Fetch all courses until we find the one with this ID
    // Note: API doesn't support single course lookup, so we page through
    let page = 1;
    let found = null;

    while (page <= 10 && !found) { // Safety limit: 10 pages = 200 courses
      const courses = await this.fetchCoursesFromApi(page);
      found = courses.find((c: any) => c.id === apiCourseId);

      if (!found && courses.length === 0) break; // No more courses
      page++;
    }

    if (!found) {
      throw new NotFoundException(`Course ${apiCourseId} not found in Golf API`);
    }

    // Transform and create course
    const courseData = this.transformApiCourse(found);
    const course = await this.prisma.course.create({
      data: courseData,
    });

    // Audit log
    await this.auditLog.log(userId, AuditAction.COURSE_CREATED, `Course:${course.id}`, {
      courseName: course.name,
      source: 'golf-api',
      apiCourseId,
    });

    return course;
  }

  /**
   * Search courses in both local DB and optionally Golf API
   */
  async searchWithApi(query: string, includeApi: boolean = false, limit: number = 10) {
    // First, search local database
    const localResults = await this.search(query, limit);

    if (!includeApi || !query || query.trim().length === 0) {
      return {
        local: localResults,
        api: [],
      };
    }

    // Fetch from API and filter client-side (API doesn't support search)
    try {
      const apiCourses = await this.fetchCoursesFromApi(1); // Get first page
      const normalizedQuery = query.trim().toLowerCase();

      // Filter API courses by name match
      const apiMatches = apiCourses
        .filter((c: any) => {
          const courseName = (c.course_name || c.club_name || '').toLowerCase();
          return courseName.includes(normalizedQuery);
        })
        .slice(0, limit)
        .map((c: any) => ({
          apiCourseId: c.id,
          name: c.course_name || c.club_name,
          city: c.location?.city,
          state: c.location?.state,
          country: c.location?.country,
          totalPar: c.tees?.male?.[0]?.par_total || null,
          source: 'api' as const,
        }));

      // Filter out API results that are already in local DB
      const localApiIds = new Set(
        localResults
          .filter((c: any) => c.apiCourseId)
          .map((c: any) => c.apiCourseId)
      );

      const uniqueApiMatches = apiMatches.filter(
        (c: any) => !localApiIds.has(c.apiCourseId)
      );

      return {
        local: localResults,
        api: uniqueApiMatches,
      };
    } catch (error) {
      console.error('Error searching Golf API:', error);
      // Fallback to local results only
      return {
        local: localResults,
        api: [],
      };
    }
  }

  /**
   * Get nearby courses sorted by distance
   * Uses Haversine formula to calculate distances
   */
  async getNearby(latitude: number, longitude: number, limit: number = 50) {
    // Get all courses with valid coordinates
    const courses = await this.prisma.course.findMany({
      where: {
        latitude: { not: null },
        longitude: { not: null },
      },
      include: {
        _count: {
          select: { rounds: true },
        },
      },
    });

    // Calculate distance for each course
    const coursesWithDistance = courses.map(course => {
      const distance = this.calculateDistance(
        latitude,
        longitude,
        course.latitude!,
        course.longitude!
      );

      return {
        id: course.id,
        name: course.name,
        city: course.city,
        state: course.state,
        country: course.country,
        latitude: course.latitude,
        longitude: course.longitude,
        totalPar: course.totalPar,
        courseRating: course.courseRating,
        slopeRating: course.slopeRating,
        timesPlayed: course._count.rounds,
        distanceMiles: Math.round(distance * 10) / 10, // Round to 1 decimal
      };
    });

    // Sort by distance and return top N
    return coursesWithDistance
      .sort((a, b) => a.distanceMiles - b.distanceMiles)
      .slice(0, limit);
  }

  /**
   * Calculate distance between two coordinates using Haversine formula
   * Returns distance in miles
   */
  private calculateDistance(
    lat1: number,
    lon1: number,
    lat2: number,
    lon2: number
  ): number {
    const R = 3959; // Earth's radius in miles
    const dLat = this.toRad(lat2 - lat1);
    const dLon = this.toRad(lon2 - lon1);

    const a =
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(this.toRad(lat1)) *
        Math.cos(this.toRad(lat2)) *
        Math.sin(dLon / 2) *
        Math.sin(dLon / 2);

    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  }

  /**
   * Convert degrees to radians
   */
  private toRad(degrees: number): number {
    return (degrees * Math.PI) / 180;
  }

  /**
   * Normalize course name to title case
   * Example: "pebble beach" -> "Pebble Beach"
   */
  private normalizeName(name: string): string {
    return name
      .trim()
      .toLowerCase()
      .split(' ')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');
  }
}

