import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import type { Request } from 'express';

const cookieExtractor = (req: Request) => req?.cookies?.lg_jwt || null;

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor() {
    super({
      jwtFromRequest: ExtractJwt.fromExtractors([
        cookieExtractor,
        ExtractJwt.fromAuthHeaderAsBearerToken(), // fallback for CLI tests
      ]),
      ignoreExpiration: false,
      secretOrKey: process.env.JWT_SECRET!,
    });
  }

  async validate(payload: any) {
    return { userId: payload.sub, email: payload.email };
  }
}

import { IsString, IsNumber, IsOptional, IsDateString, MaxLength, Min, Max } from 'class-validator';

export class CreateRoundDto {
  @IsOptional()
  @IsString()
  courseId?: string;    // Course ID from Course table (preferred)

  @IsOptional()
  @IsString()
  @MaxLength(100)
  courseName?: string;  // Course name (deprecated, but kept for compatibility)

  @IsNumber()
  @Min(18)
  @Max(200)
  strokes!: number;     // e.g., 83

  @IsOptional()
  @IsNumber()
  @Min(9)
  @Max(100)
  front9?: number;      // Front 9 score (optional)

  @IsOptional()
  @IsNumber()
  @Min(9)
  @Max(100)
  back9?: number;       // Back 9 score (optional)

  @IsOptional()
  @IsString()
  @MaxLength(200)
  playingPartners?: string;  // Comma-separated list of playing partners

  @IsOptional()
  @IsDateString()
  date?: string;        // ISO date, optional

  @IsOptional()
  @IsDateString()
  teeTime?: string;     // Tee time for auto-linking (ISO datetime)

  @IsOptional()
  @IsNumber()
  @Min(-90)
  @Max(90)
  latitude?: number;    // GPS latitude

  @IsOptional()
  @IsNumber()
  @Min(-180)
  @Max(180)
  longitude?: number;   // GPS longitude

  @IsOptional()
  @IsString()
  @MaxLength(500)
  notes?: string;       // optional

  // Advanced Golf Stats (12 fields)
  // Performance Metrics
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  girPct?: number;      // Greens in Regulation % (0-100)

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  firPct?: number;      // Fairways in Regulation % (0-100)

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  approachPct?: number; // Approach shot accuracy % (0-100)

  // Putting Stats
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(50)
  front9Putts?: number; // Front 9 putting

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(50)
  back9Putts?: number;  // Back 9 putting

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  totalPutts?: number;  // Total putts (can be auto-calc from F9+B9)

  // Scoring Breakdown
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  holeInOnes?: number;  // Hole-in-one count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  eagles?: number;      // Eagle count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  birdies?: number;     // Birdie count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  pars?: number;        // Par count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  bogeys?: number;      // Bogey count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  doubleBogeys?: number; // Double bogey count

  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(18)
  triplePlusBogeys?: number; // Triple bogey+ count
}

import { Type } from 'class-transformer';
import { IsNumber, IsOptional, IsString, Max, Min } from 'class-validator';

export class UpdateProfileDto {
  @IsOptional()
  @IsString()
  firstName?: string;

  @IsOptional()
  @IsString()
  lastName?: string;

  @IsOptional()
  @IsString()
  ghinNumber?: string; // empty string will be treated as null server-side

  // With transform enabled globally, this will coerce "12.3" -> 12.3
  @IsOptional()
  @Type(() => Number)
  @IsNumber()
  @Min(-10)  // generous lower bound; GHIN can be +handicaps
  @Max(54)   // common upper bound
  handicap?: number | null;
}

