import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

export enum AuditAction {
  // Auth events
  LOGIN = 'LOGIN',
  LOGOUT = 'LOGOUT',
  AUTH_FAILED = 'AUTH_FAILED',

  // Profile events
  PROFILE_UPDATED = 'PROFILE_UPDATED',
  PROFILE_VIEWED = 'PROFILE_VIEWED',

  // Round events
  ROUND_CREATED = 'ROUND_CREATED',
  ROUND_UPDATED = 'ROUND_UPDATED',
  ROUND_VIEWED = 'ROUND_VIEWED',
  ROUND_DELETED = 'ROUND_DELETED',

  // Course events
  COURSE_CREATED = 'COURSE_CREATED',
  COURSE_UPDATED = 'COURSE_UPDATED',
  COURSE_DELETED = 'COURSE_DELETED',

  // Account events
  ACCOUNT_DELETED = 'ACCOUNT_DELETED',
  DATA_EXPORTED = 'DATA_EXPORTED',
}

export interface AuditLogMetadata {
  ip?: string;
  userAgent?: string;
  changedFields?: string[];
  oldValues?: Record<string, any>;
  newValues?: Record<string, any>;
  resourceId?: string;
  error?: string;
  [key: string]: any;
}

@Injectable()
export class AuditLogService {
  constructor(private prisma: PrismaService) {}

  /**
   * Create an audit log entry
   * @param userId - The user who performed the action
   * @param action - The action performed (use AuditAction enum)
   * @param resource - The resource affected (e.g., 'Round:uuid', 'Profile:uuid')
   * @param metadata - Additional context (IP, user agent, changed fields, etc.)
   */
  async log(
    userId: string,
    action: AuditAction,
    resource?: string,
    metadata?: AuditLogMetadata,
  ): Promise<void> {
    try {
      await this.prisma.auditLog.create({
        data: {
          userId,
          action,
          resource: resource || null,
          metadata: metadata ? (metadata as any) : undefined,
        },
      });
    } catch (error) {
      // Log to console if audit logging fails (don't block the main operation)
      console.error('Failed to create audit log:', error);
    }
  }

  /**
   * Get audit logs for a specific user
   * @param userId - The user ID
   * @param limit - Maximum number of logs to return
   */
  async getUserLogs(userId: string, limit = 100) {
    return this.prisma.auditLog.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: limit,
    });
  }

  /**
   * Get audit logs by action type
   * @param action - The action type
   * @param limit - Maximum number of logs to return
   */
  async getLogsByAction(action: AuditAction, limit = 100) {
    return this.prisma.auditLog.findMany({
      where: { action },
      orderBy: { createdAt: 'desc' },
      take: limit,
    });
  }

  /**
   * Delete old audit logs (for cleanup/retention policy)
   * @param olderThanDays - Delete logs older than this many days (default: 90)
   */
  async cleanupOldLogs(olderThanDays = 90): Promise<number> {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - olderThanDays);

    const result = await this.prisma.auditLog.deleteMany({
      where: {
        createdAt: {
          lt: cutoffDate,
        },
      },
    });

    return result.count;
  }
}

