// src/config/env.validation.ts
/**
 * Environment Variable Validation
 *
 * Validates that all required environment variables are set at startup.
 * Fails fast with helpful error messages if configuration is invalid.
 */

interface EnvConfig {
  DATABASE_URL: string;
  JWT_SECRET: string;
  GOOGLE_CLIENT_ID: string;
  GOOGLE_CLIENT_SECRET: string;
  GOOGLE_CALLBACK_URL: string;
  FRONTEND_URL: string;
  NODE_ENV: 'development' | 'production' | 'test';
  PORT: string;
}

interface ValidationRule {
  name: keyof EnvConfig;
  required: boolean;
  validator?: (value: string) => { valid: boolean; error?: string };
}

const validationRules: ValidationRule[] = [
  {
    name: 'DATABASE_URL',
    required: true,
    validator: (value) => {
      if (!value.startsWith('postgresql://')) {
        return {
          valid: false,
          error: 'DATABASE_URL must start with postgresql://',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'JWT_SECRET',
    required: true,
    validator: (value) => {
      if (value.length < 32) {
        return {
          valid: false,
          error: 'JWT_SECRET must be at least 32 characters. Generate with: openssl rand -base64 32',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'GOOGLE_CLIENT_ID',
    required: true,
    validator: (value) => {
      if (!value.includes('.apps.googleusercontent.com')) {
        return {
          valid: false,
          error: 'GOOGLE_CLIENT_ID should end with .apps.googleusercontent.com',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'GOOGLE_CLIENT_SECRET',
    required: true,
    validator: (value) => {
      if (value.length < 10) {
        return {
          valid: false,
          error: 'GOOGLE_CLIENT_SECRET appears too short',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'GOOGLE_CALLBACK_URL',
    required: true,
    validator: (value) => {
      if (!value.includes('/auth/google/redirect')) {
        return {
          valid: false,
          error: 'GOOGLE_CALLBACK_URL should include /auth/google/redirect',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'FRONTEND_URL',
    required: true,
    validator: (value) => {
      if (!value.startsWith('http://') && !value.startsWith('https://')) {
        return {
          valid: false,
          error: 'FRONTEND_URL must start with http:// or https://',
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'NODE_ENV',
    required: true,
    validator: (value) => {
      const validEnvs = ['development', 'production', 'test'];
      if (!validEnvs.includes(value)) {
        return {
          valid: false,
          error: `NODE_ENV must be one of: ${validEnvs.join(', ')}`,
        };
      }
      return { valid: true };
    },
  },
  {
    name: 'PORT',
    required: true,
    validator: (value) => {
      const port = parseInt(value, 10);
      if (isNaN(port) || port < 1 || port > 65535) {
        return {
          valid: false,
          error: 'PORT must be a valid port number (1-65535)',
        };
      }
      return { valid: true };
    },
  },
];

/**
 * Validate all required environment variables
 * Throws an error with detailed messages if any validation fails
 */
export function validateEnvironment(): void {
  const errors: string[] = [];

  for (const rule of validationRules) {
    const value = process.env[rule.name];

    // Check if required variable is missing
    if (rule.required && !value) {
      errors.push(`❌ ${rule.name} is required but not set`);
      continue;
    }

    // Run custom validator if present
    if (value && rule.validator) {
      const result = rule.validator(value);
      if (!result.valid) {
        errors.push(`❌ ${rule.name}: ${result.error}`);
      }
    }
  }

  if (errors.length > 0) {
    const errorMessage = [
      '',
      '🔴 Environment Variable Validation Failed',
      '='.repeat(50),
      '',
      ...errors,
      '',
      '📝 Fix these issues in your .env file',
      '💡 See .env.example for reference',
      '',
    ].join('\n');

    throw new Error(errorMessage);
  }

  console.log('✅ Environment variables validated successfully');
}

/**
 * Get validated environment configuration
 * Use this instead of accessing process.env directly
 */
export function getEnvConfig(): EnvConfig {
  return {
    DATABASE_URL: process.env.DATABASE_URL!,
    JWT_SECRET: process.env.JWT_SECRET!,
    GOOGLE_CLIENT_ID: process.env.GOOGLE_CLIENT_ID!,
    GOOGLE_CLIENT_SECRET: process.env.GOOGLE_CLIENT_SECRET!,
    GOOGLE_CALLBACK_URL: process.env.GOOGLE_CALLBACK_URL!,
    FRONTEND_URL: process.env.FRONTEND_URL!,
    NODE_ENV: process.env.NODE_ENV as 'development' | 'production' | 'test',
    PORT: process.env.PORT!,
  };
}

