// src/auth/admin.guard.ts
import {
  CanActivate,
  ExecutionContext,
  Injectable,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

/**
 * Admin Guard - Ensures user has admin role
 *
 * This guard must be used AFTER JwtAuthGuard since it requires req.user to be populated
 *
 * Usage:
 * @UseGuards(JwtAuthGuard, AdminGuard)
 */
@Injectable()
export class AdminGuard implements CanActivate {
  private readonly logger = new Logger(AdminGuard.name);

  constructor(private readonly prisma: PrismaService) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const user = request.user;

    if (!user || !user.userId) {
      throw new ForbiddenException('Authentication required');
    }

    // Check if user has admin role
    const hasAdminRole = await this.hasRole(user.userId, 'admin');

    if (!hasAdminRole) {
      this.logger.warn(
        `User ${user.userId} (${user.email}) attempted admin-only action without admin role`,
      );
      throw new ForbiddenException(
        'Admin access required. This action is restricted to administrators.',
      );
    }

    return true;
  }

  /**
   * Check if user has a specific role
   */
  private async hasRole(userId: string, roleName: string): Promise<boolean> {
    const userRole = await this.prisma.userRole.findFirst({
      where: {
        userId,
        role: {
          name: roleName,
        },
      },
      include: {
        role: true,
      },
    });

    return !!userRole;
  }
}

