     3→import { PassportStrategy } from '@nestjs/passport';
     4→import { Strategy, Profile, VerifyCallback } from 'passport-google-oauth20';
     5→
     6→type GoogleUser = {
     7→  provider: 'google';
     8→  providerId: string;
     9→  email?: string;
    10→  firstName?: string;
    11→  lastName?: string;
    12→  picture?: string;
    13→  locale?: string;
    14→  emailVerified?: boolean;
    15→  hostedDomain?: string;
    16→};
    17→
    18→@Injectable()
    19→export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
    20→  constructor() {
    21→    super({
    22→      clientID: process.env.GOOGLE_CLIENT_ID!,
    23→      clientSecret: process.env.GOOGLE_CLIENT_SECRET!,
    24→      callbackURL:
    25→        process.env.GOOGLE_CALLBACK_URL ||
    26→        'https://api.lazygolfing.com/auth/google/redirect',
    27→      scope: ['openid', 'profile', 'email'],
    28→      // NOTE: no `state: true` (we're not using sessions)
    29→      // prompt: 'select_account', // optional: always show account chooser
    30→    });
    31→  }
    32→
    33→  async validate(
    34→    accessToken: string,
    35→    refreshToken: string,
    36→    profile: Profile & { _json?: any },
    37→    done: VerifyCallback,
    38→  ): Promise<void> {
    39→    const { id, name, emails, photos, _json } = profile;
    40→
    41→    const user: GoogleUser = {
    42→      provider: 'google',
    43→      providerId: id,
    44→      email: emails?.[0]?.value ?? _json?.email,
