// src/auth/google.strategy.ts
import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, Profile, VerifyCallback } from 'passport-google-oauth20';

type GoogleUser = {
  provider: 'google';
  providerId: string;
  email?: string;
  firstName?: string;
  lastName?: string;
  picture?: string;
  locale?: string;
  emailVerified?: boolean;
  hostedDomain?: string;
};

@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  constructor() {
    super({
      clientID: process.env.GOOGLE_CLIENT_ID!,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET!,
      callbackURL:
        process.env.GOOGLE_CALLBACK_URL ||
        'https://api.lazygolfing.com/auth/google/redirect',
      scope: ['openid', 'profile', 'email'],
      // NOTE: no `state: true` (we're not using sessions)
      // prompt: 'select_account', // optional: always show account chooser
    });
  }

  async validate(
    accessToken: string,
    refreshToken: string,
    profile: Profile & { _json?: any },
    done: VerifyCallback,
  ): Promise<void> {
    const { id, name, emails, photos, _json } = profile;

    const user: GoogleUser = {
      provider: 'google',
      providerId: id,
      email: emails?.[0]?.value ?? _json?.email,
      firstName: name?.givenName ?? _json?.given_name,
      lastName: name?.familyName ?? _json?.family_name,
      picture: photos?.[0]?.value ?? _json?.picture,
      locale: _json?.locale,
      emailVerified: Boolean(_json?.email_verified),
      hostedDomain: _json?.hd,
    };

    return done(null, user);
  }
}

