// src/auth/csrf.guard.ts
import {
  CanActivate,
  ExecutionContext,
  Injectable,
  ForbiddenException,
} from '@nestjs/common';
import type { Request } from 'express';

/**
 * CSRF Guard using double-submit cookie pattern
 *
 * This guard protects against Cross-Site Request Forgery attacks by:
 * 1. Requiring a CSRF token to be sent in both a cookie and a header
 * 2. Verifying that both values match
 * 3. Only protecting state-changing operations (POST, PUT, PATCH, DELETE)
 *
 * How it works:
 * - The CSRF token is generated and set as a cookie during login/auth
 * - Frontend must read this cookie and send it back in the X-CSRF-Token header
 * - Since malicious sites cannot read cookies from other domains due to Same-Origin Policy,
 *   they cannot obtain the token to include in the header
 */
@Injectable()
export class CsrfGuard implements CanActivate {
  canActivate(context: ExecutionContext): boolean {
    const request = context.switchToHttp().getRequest<Request>();
    const method = request.method.toUpperCase();

    // Only protect state-changing methods
    // GET, HEAD, OPTIONS are considered safe
    if (['GET', 'HEAD', 'OPTIONS'].includes(method)) {
      return true;
    }

    // Extract CSRF token from cookie
    const csrfCookie = (request as any).cookies?.csrf_token;

    // Extract CSRF token from header
    const csrfHeader = request.headers['x-csrf-token'] as string;

    // Both must exist
    if (!csrfCookie || !csrfHeader) {
      throw new ForbiddenException(
        'CSRF token missing. Please include X-CSRF-Token header.',
      );
    }

    // Both must match (constant-time comparison to prevent timing attacks)
    if (!this.constantTimeCompare(csrfCookie, csrfHeader)) {
      throw new ForbiddenException('CSRF token mismatch');
    }

    return true;
  }

  /**
   * Constant-time string comparison to prevent timing attacks
   * Always compares all characters even if a mismatch is found early
   */
  private constantTimeCompare(a: string, b: string): boolean {
    if (a.length !== b.length) {
      return false;
    }

    let mismatch = 0;
    for (let i = 0; i < a.length; i++) {
      mismatch |= a.charCodeAt(i) ^ b.charCodeAt(i);
    }

    return mismatch === 0;
  }
}
